 &lt;h5 id=&#34;监控指标&#34;&gt;&lt;a href=&#34;#监控指标&#34; class=&#34;headerlink&#34; title=&#34;监控指标&#34;&gt;&lt;/a&gt;监控指标&lt;/h5&gt;&lt;ul&gt;
&lt;li&gt;性能指标：Performance&lt;/li&gt;
&lt;li&gt;内存指标: Memory&lt;/li&gt;
&lt;li&gt;基本活动指标：Basic activity&lt;/li&gt;
&lt;li&gt;持久性指标: Persistence&lt;/li&gt;
&lt;li&gt;错误指标：Error&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;h5 id=&#34;性能指标：Performance&#34;&gt;&lt;a href=&#34;#性能指标：Performance&#34; class=&#34;headerlink&#34; title=&#34;性能指标：Performance&#34;&gt;&lt;/a&gt;性能指标：Performance&lt;/h5&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Name&lt;/th&gt;
&lt;th&gt;Description&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;&lt;tr&gt;
&lt;td&gt;latency&lt;/td&gt;
&lt;td&gt;Redis响应一个请求的时间&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;instantaneous_ops_per_sec&lt;/td&gt;
&lt;td&gt;平均每秒处理请求总数&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;hi rate(calculated)&lt;/td&gt;
&lt;td&gt;缓存命中率（计算出来的&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;&lt;/table&gt;
&lt;h5 id=&#34;内存指标-Memory&#34;&gt;&lt;a href=&#34;#内存指标-Memory&#34; class=&#34;headerlink&#34; title=&#34;内存指标: Memory&#34;&gt;&lt;/a&gt;内存指标: Memory&lt;/h5&gt;&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Name&lt;/th&gt;
&lt;th&gt;Description&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;&lt;tr&gt;
&lt;td&gt;used_memory&lt;/td&gt;
&lt;td&gt;已使用内存&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;mem_fragmentation_ratio&lt;/td&gt;
&lt;td&gt;内存碎片率&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;evicted_keys&lt;/td&gt;
&lt;td&gt;由于最大内存限制被移除的key的数量&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;blocked_clients&lt;/td&gt;
&lt;td&gt;由于BLPOP,BRPOP,or BRPOPLPUSH而备阻塞的客户端&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;&lt;/table&gt;
&lt;h5 id=&#34;基本活动指标：Basic-activity&#34;&gt;&lt;a href=&#34;#基本活动指标：Basic-activity&#34; class=&#34;headerlink&#34; title=&#34;基本活动指标：Basic activity&#34;&gt;&lt;/a&gt;基本活动指标：Basic activity&lt;/h5&gt;&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Name&lt;/th&gt;
&lt;th&gt;Description&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;&lt;tr&gt;
&lt;td&gt;connected_clients&lt;/td&gt;
&lt;td&gt;客户端连接数&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;conected_laves&lt;/td&gt;
&lt;td&gt;slave数量&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;master_last_io_seconds_ago&lt;/td&gt;
&lt;td&gt;最近一次主从交互之后的秒数&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;keyspace&lt;/td&gt;
&lt;td&gt;数据库中的key值总数&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;&lt;/table&gt;
&lt;h5 id=&#34;持久性指标-Persistence&#34;&gt;&lt;a href=&#34;#持久性指标-Persistence&#34; class=&#34;headerlink&#34; title=&#34;持久性指标: Persistence&#34;&gt;&lt;/a&gt;持久性指标: Persistence&lt;/h5&gt;&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Name&lt;/th&gt;
&lt;th&gt;Description&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;&lt;tr&gt;
&lt;td&gt;rdb_last_save_time&lt;/td&gt;
&lt;td&gt;最后一次持久化保存磁盘的时间戳&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;rdb_changes_sice_last_save&lt;/td&gt;
&lt;td&gt;自最后一次持久化以来数据库的更改数&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;&lt;/table&gt;
&lt;h5 id=&#34;错误指标：Error&#34;&gt;&lt;a href=&#34;#错误指标：Error&#34; class=&#34;headerlink&#34; title=&#34;错误指标：Error&#34;&gt;&lt;/a&gt;错误指标：Error&lt;/h5&gt;&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Name&lt;/th&gt;
&lt;th&gt;Description&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;&lt;tr&gt;
&lt;td&gt;rejected_connections&lt;/td&gt;
&lt;td&gt;由于达到maxclient限制而被拒绝的连接数&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;keyspace_misses&lt;/td&gt;
&lt;td&gt;key值查找失败(没有命中)次数&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;master_link_down_since_seconds&lt;/td&gt;
&lt;td&gt;主从断开的持续时间（以秒为单位)&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;&lt;/table&gt;
&lt;h5 id=&#34;监控方式&#34;&gt;&lt;a href=&#34;#监控方式&#34; class=&#34;headerlink&#34; title=&#34;监控方式&#34;&gt;&lt;/a&gt;监控方式&lt;/h5&gt;&lt;ul&gt;
&lt;li&gt;redis-benchmark&lt;/li&gt;
&lt;li&gt;redis-stat&lt;/li&gt;
&lt;li&gt;redis-faina&lt;/li&gt;
&lt;li&gt;redislive&lt;/li&gt;
&lt;li&gt;redis-cli&lt;/li&gt;
&lt;li&gt;monitor&lt;/li&gt;
&lt;li&gt;showlog&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;1.get：获取慢查询日志&lt;/p&gt;
&lt;p&gt;2.len：获取慢查询日志条目数&lt;/p&gt;
&lt;p&gt;3.reset：重置慢查询日志&lt;/p&gt;
&lt;p&gt;相关配置：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;slowlog-log-slower-than 1000 # 设置慢查询的时间下线，单位：微秒
slowlog-max-len 100 # 设置慢查询命令对应的日志显示长度，单位：命令数&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;info（可以一次性获取所有的信息，也可以按块获取信息）&lt;/p&gt;
&lt;p&gt;1.server:服务器运行的环境参数&lt;/p&gt;
&lt;p&gt;2.clients:客户端相关信息&lt;/p&gt;
&lt;p&gt;3.memory：服务器运行内存统计数据&lt;/p&gt;
&lt;p&gt;4.persistence：持久化信息&lt;/p&gt;
&lt;p&gt;5.stats：通用统计数据&lt;/p&gt;
&lt;p&gt;6.Replication：主从复制相关信息&lt;/p&gt;
&lt;p&gt;7.CPU：CPU使用情况&lt;/p&gt;
&lt;p&gt;8.cluster：集群信息&lt;/p&gt;
&lt;p&gt;9.Keypass：键值对统计数量信息&lt;/p&gt;
&lt;h5 id=&#34;终端info命令使用&#34;&gt;&lt;a href=&#34;#终端info命令使用&#34; class=&#34;headerlink&#34; title=&#34;终端info命令使用&#34;&gt;&lt;/a&gt;终端info命令使用&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;./redis-cli info 按块获取信息 | grep 需要过滤的参数

./redis-cli info stats | grep ops&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;交互式info命令使用&#34;&gt;&lt;a href=&#34;#交互式info命令使用&#34; class=&#34;headerlink&#34; title=&#34;交互式info命令使用&#34;&gt;&lt;/a&gt;交互式info命令使用&lt;/h5&gt;&lt;pre&gt;&lt;code&gt; #./redis-cli 
&amp;gt; info server&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;性能监控：&#34;&gt;&lt;a href=&#34;#性能监控：&#34; class=&#34;headerlink&#34; title=&#34;性能监控：&#34;&gt;&lt;/a&gt;性能监控：&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;redis-cli info | grep ops # 每秒操作数&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;内存监控&#34;&gt;&lt;a href=&#34;#内存监控&#34; class=&#34;headerlink&#34; title=&#34;内存监控&#34;&gt;&lt;/a&gt;内存监控&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep used | grep human       
used_memory_human:2.99M  # 内存分配器从操作系统分配的内存总量
used_memory_rss_human:8.04M  #操作系统看到的内存占用，top命令看到的内存
used_memory_peak_human:7.77M # redis内存消耗的峰值
used_memory_lua_human:37.00K   # lua脚本引擎占用的内存大小&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;由于BLPOP-BRPOP-or-BRPOPLPUSH而备阻塞的客户端&#34;&gt;&lt;a href=&#34;#由于BLPOP-BRPOP-or-BRPOPLPUSH而备阻塞的客户端&#34; class=&#34;headerlink&#34; title=&#34;由于BLPOP,BRPOP,or BRPOPLPUSH而备阻塞的客户端&#34;&gt;&lt;/a&gt;由于BLPOP,BRPOP,or BRPOPLPUSH而备阻塞的客户端&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep blocked_clients
blocked_clients:0  &lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;由于最大内存限制被移除的key的数量&#34;&gt;&lt;a href=&#34;#由于最大内存限制被移除的key的数量&#34; class=&#34;headerlink&#34; title=&#34;由于最大内存限制被移除的key的数量&#34;&gt;&lt;/a&gt;由于最大内存限制被移除的key的数量&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep evicted_keys
evicted_keys:0  #&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;内存碎片率&#34;&gt;&lt;a href=&#34;#内存碎片率&#34; class=&#34;headerlink&#34; title=&#34;内存碎片率&#34;&gt;&lt;/a&gt;内存碎片率&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep mem_fragmentation_ratio
mem_fragmentation_ratio:2.74 &lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;已使用内存&#34;&gt;&lt;a href=&#34;#已使用内存&#34; class=&#34;headerlink&#34; title=&#34;已使用内存&#34;&gt;&lt;/a&gt;已使用内存&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep used_memory:
used_memory:3133624  &lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;基本活动指标：&#34;&gt;&lt;a href=&#34;#基本活动指标：&#34; class=&#34;headerlink&#34; title=&#34;基本活动指标：&#34;&gt;&lt;/a&gt;基本活动指标：&lt;/h5&gt;&lt;p&gt;redis连接了多少客户端 通过观察其数量可以确认是否存在意料之外的连接。如果发现数量不对劲，就可以使用lcient list指令列出所有的客户端链接地址来确定源头。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep connected_clients
connected_clients:1


[root@CombCloud-2020110836 src]# ./redis-cli info | grep connected
connected_clients:1   # 客户端连接数量
connected_slaves:1   # slave连接数量&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;持久性指标：&#34;&gt;&lt;a href=&#34;#持久性指标：&#34; class=&#34;headerlink&#34; title=&#34;持久性指标：&#34;&gt;&lt;/a&gt;持久性指标：&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep rdb_last_save_time
rdb_last_save_time:1591876204  # 最后一次持久化保存磁盘的时间戳
[root@CombCloud-2020110836 src]# ./redis-cli info | grep rdb_changes_since_last_save
rdb_changes_since_last_save:0   # 自最后一次持久化以来数据库的更改数&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;错误指标&#34;&gt;&lt;a href=&#34;#错误指标&#34; class=&#34;headerlink&#34; title=&#34;错误指标&#34;&gt;&lt;/a&gt;错误指标&lt;/h5&gt;&lt;p&gt;由于超出最大连接数限制而被拒绝的客户端连接次数，如果这个数字很大，则意味着服务器的最大连接数设置得过低，需要调整maxclients&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep connected_clients
connected_clients:1&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;key值查找失败(没有命中)次数，出现多次可能是被hei ke gongjji&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep keyspace
keyspace_misses:0   &lt;/code&gt;&lt;/pre&gt;&lt;p&gt;主从断开的持续时间（以秒为单位)&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep rdb_changes_since_last_save
rdb_changes_since_last_save:0  &lt;/code&gt;&lt;/pre&gt;&lt;p&gt;复制积压缓冲区如果设置得太小，会导致里面的指令被覆盖掉找不到偏移量，从而触发全量同步&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep backlog_size
repl_backlog_size:1048576&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;通过查看sync_partial_err变量的次数来决定是否需要扩大积压缓冲区，它表示主从半同步复制失败的次数&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep sync_partial_err
sync_partial_err:1&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;redis性能测试命令&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;./redis-benchmark -c 100 -n 5000&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;原创地址：&lt;a href=&#34;https://mp.weixin.qq.com/s/gu1ZLXlR9ud4wnssYMVkMw&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;https://mp.weixin.qq.com/s/gu1ZLXlR9ud4wnssYMVkMw&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;学Python，想必大家都是从爬虫开始的吧。毕竟网上类似的资源很丰富，开源项目也非常多。&lt;/p&gt;
&lt;p&gt;Python学习网络爬虫主要分3个大的版块：抓取，分析，存储&lt;/p&gt;
&lt;p&gt;当我们在浏览器中输入一个url后回车，后台会发生什么？&lt;/p&gt;
&lt;p&gt;简单来说这段过程发生了以下四个步骤：&lt;/p&gt;
&lt;p&gt;查找域名对应的IP地址。&lt;br&gt;向IP对应的服务器发送请求。&lt;br&gt;服务器响应请求，发回网页内容。&lt;br&gt;浏览器解析网页内容。&lt;/p&gt;
&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;p&gt;那么学习爬虫需要掌握哪些库呢&lt;/p&gt;
&lt;p&gt;通用：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;urllib -网络库(stdlib)。&lt;/li&gt;
&lt;li&gt;requests -网络库。&lt;/li&gt;
&lt;li&gt;grab – 网络库（基于pycurl）。&lt;/li&gt;
&lt;li&gt;pycurl – 网络库（绑定libcurl）。&lt;/li&gt;
&lt;li&gt;urllib3 – Python HTTP库，安全连接池、支持文件post、可用性高。&lt;/li&gt;
&lt;li&gt;httplib2 – 网络库。&lt;/li&gt;
&lt;li&gt;RoboBrowser – 一个简单的、极具Python风格的Python库，无需独立的浏览器即可浏览网页。&lt;/li&gt;
&lt;li&gt;MechanicalSoup -一个与网站自动交互Python库。&lt;/li&gt;
&lt;li&gt;mechanize -有状态、可编程的Web浏览库。&lt;/li&gt;
&lt;li&gt;socket – 底层网络接口(stdlib)。&lt;/li&gt;
&lt;li&gt;Unirest for Python – Unirest是一套可用于多种语言的轻量级的HTTP库。&lt;/li&gt;
&lt;li&gt;hyper – Python的HTTP/2客户端。&lt;/li&gt;
&lt;li&gt;PySocks – SocksiPy更新并积极维护的版本，包括错误修复和一些其他的特征。作为socket模块的直接替换。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;网络爬虫框架&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;功能齐全的爬虫&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;grab – 网络爬虫框架（基于pycurl/multicur）&lt;/li&gt;
&lt;li&gt;scrapy – 网络爬虫框架（基于twisted），不支持Python3。&lt;/li&gt;
&lt;li&gt;pyspider – 一个强大的爬虫系统。&lt;/li&gt;
&lt;li&gt;cola – 一个分布式爬虫框架。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;其他&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;portia – 基于Scrapy的可视化爬虫。&lt;/li&gt;
&lt;li&gt;restkit – Python的HTTP资源工具包。它可以让你轻松地访问HTTP资源，并围绕它建立的对象。&lt;/li&gt;
&lt;li&gt;demiurge – 基于PyQuery的爬虫微框架。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;HTML/XML解析器&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;通用&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;lxml – C语言编写高效HTML/ XML处理库。支持XPath。&lt;/li&gt;
&lt;li&gt;cssselect – 解析DOM树和CSS选择器。&lt;/li&gt;
&lt;li&gt;pyquery – 解析DOM树和jQuery选择器。&lt;/li&gt;
&lt;li&gt;BeautifulSoup – 低效HTML/ XML处理库，纯Python实现。&lt;/li&gt;
&lt;li&gt;html5lib – 根据WHATWG规范生成HTML/ XML文档的DOM。该规范被用在现在所有的浏览器上。&lt;/li&gt;
&lt;li&gt;feedparser – 解析RSS/ATOM feeds。&lt;/li&gt;
&lt;li&gt;MarkupSafe – 为XML/HTML/XHTML提供了安全转义的字符串。&lt;/li&gt;
&lt;li&gt;xmltodict – 一个可以让你在处理XML时感觉像在处理JSON一样的Python模块。&lt;/li&gt;
&lt;li&gt;xhtml2pdf – 将HTML/CSS转换为PDF。&lt;/li&gt;
&lt;li&gt;untangle – 轻松实现将XML文件转换为Python对象。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;清理&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Bleach – 清理HTML（需要html5lib）。&lt;/li&gt;
&lt;li&gt;sanitize – 为混乱的数据世界带来清明。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;文本处理&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;用于解析和操作简单文本的库。&lt;ul&gt;
&lt;li&gt;通用&lt;ul&gt;
&lt;li&gt;difflib – （Python标准库）帮助进行差异化比较。&lt;/li&gt;
&lt;li&gt;Levenshtein – 快速计算Levenshtein距离和字符串相似度。&lt;/li&gt;
&lt;li&gt;fuzzywuzzy – 模糊字符串匹配。&lt;/li&gt;
&lt;li&gt;esmre – 正则表达式加速器。&lt;/li&gt;
&lt;li&gt;ftfy – 自动整理Unicode文本，减少碎片化。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;自然语言处理&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;处理人类语言问题的库。&lt;ul&gt;
&lt;li&gt;NLTK -编写Python程序来处理人类语言数据的最好平台。&lt;/li&gt;
&lt;li&gt;Pattern – Python的网络挖掘模块。他有自然语言处理工具，机器学习以及其它。&lt;/li&gt;
&lt;li&gt;TextBlob – 为深入自然语言处理任务提供了一致的API。是基于NLTK以及Pattern的巨人之肩上发展的。&lt;/li&gt;
&lt;li&gt;jieba – 中文分词工具。&lt;/li&gt;
&lt;li&gt;SnowNLP – 中文文本处理库。&lt;/li&gt;
&lt;li&gt;loso – 另一个中文分词库。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;浏览器自动化与仿真&lt;ul&gt;
&lt;li&gt;selenium – 自动化真正的浏览器（Chrome浏览器，火狐浏览器，Opera浏览器，IE浏览器）。&lt;/li&gt;
&lt;li&gt;Ghost.py – 对PyQt的webkit的封装（需要PyQT）。&lt;/li&gt;
&lt;li&gt;Spynner – 对PyQt的webkit的封装（需要PyQT）。&lt;/li&gt;
&lt;li&gt;Splinter – 通用API浏览器模拟器（selenium web驱动，Django客户端，Zope）。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;多重处理&lt;ul&gt;
&lt;li&gt;threading – Python标准库的线程运行。对于I/O密集型任务很有效。对于CPU绑定的任务没用，因为python GIL。&lt;/li&gt;
&lt;li&gt;multiprocessing – 标准的Python库运行多进程。&lt;/li&gt;
&lt;li&gt;celery – 基于分布式消息传递的异步任务队列/作业队列。&lt;/li&gt;
&lt;li&gt;concurrent-futures – concurrent-futures 模块为调用异步执行提供了一个高层次的接口。&lt;br&gt;异步&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ul&gt;
&lt;li&gt;异步网络编程库&lt;ul&gt;
&lt;li&gt;asyncio – （在Python 3.4 +版本以上的 Python标准库）异步I/O，时间循环，协同程序和任务。&lt;/li&gt;
&lt;li&gt;Twisted – 基于事件驱动的网络引擎框架。&lt;/li&gt;
&lt;li&gt;Tornado – 一个网络框架和异步网络库。&lt;/li&gt;
&lt;li&gt;pulsar – Python事件驱动的并发框架。&lt;/li&gt;
&lt;li&gt;diesel – Python的基于绿色事件的I/O框架。&lt;/li&gt;
&lt;li&gt;gevent – 一个使用greenlet 的基于协程的Python网络库。&lt;/li&gt;
&lt;li&gt;eventlet – 有WSGI支持的异步框架。&lt;/li&gt;
&lt;li&gt;Tomorrow – 异步代码的奇妙的修饰语法。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;队列&lt;ul&gt;
&lt;li&gt;celery – 基于分布式消息传递的异步任务队列/作业队列。&lt;/li&gt;
&lt;li&gt;huey – 小型多线程任务队列。&lt;/li&gt;
&lt;li&gt;mrq – Mr. Queue – 使用redis &amp;amp; Gevent 的Python分布式工作任务队列。&lt;/li&gt;
&lt;li&gt;RQ – 基于Redis的轻量级任务队列管理器。&lt;/li&gt;
&lt;li&gt;simpleq – 一个简单的，可无限扩展，基于Amazon SQS的队列。&lt;/li&gt;
&lt;li&gt;python-gearman – Gearman的Python API。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;云计算&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;picloud – 云端执行Python代码。&lt;/li&gt;
&lt;li&gt;dominoup.com – 云端执行R，Python和matlab代码&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;网页内容提取&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;HTML页面的文本和元数据&lt;/li&gt;
&lt;li&gt;newspaper – 用Python进行新闻提取、文章提取和内容策展。&lt;/li&gt;
&lt;li&gt;html2text – 将HTML转为Markdown格式文本。&lt;/li&gt;
&lt;li&gt;python-goose – HTML内容/文章提取器。&lt;/li&gt;
&lt;li&gt;lassie – 人性化的网页内容检索工具&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;WebSocket&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;用于WebSocket的库。&lt;ul&gt;
&lt;li&gt;Crossbar – 开源的应用消息传递路由器（Python实现的用于Autobahn的WebSocket和WAMP）。&lt;/li&gt;
&lt;li&gt;AutobahnPython – 提供了WebSocket协议和WAMP协议的Python实现并且开源。&lt;/li&gt;
&lt;li&gt;WebSocket-for-Python – Python 2和3以及PyPy的WebSocket客户端和服务器库。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;DNS解析&lt;ul&gt;
&lt;li&gt;dnsyo – 在全球超过1500个的DNS服务器上检查你的DNS。&lt;/li&gt;
&lt;li&gt;pycares – c-ares的接口。c-ares是进行DNS请求和异步名称决议的C语言库。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;计算机视觉&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;OpenCV – 开源计算机视觉库。&lt;/li&gt;
&lt;li&gt;SimpleCV – 用于照相机、图像处理、特征提取、格式转换的简介，可读性强的接口（基于OpenCV）。&lt;/li&gt;
&lt;li&gt;mahotas – 快速计算机图像处理算法（完全使用 C++ 实现），完全基于 numpy 的数组作为它的数据类型。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;代理服务器&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;shadowsocks – 一个快速隧道代理，可帮你穿透防火墙（支持TCP和UDP，TFO，多用户和平滑重启，目的IP黑名单）。&lt;/li&gt;
&lt;li&gt;tproxy – tproxy是一个简单的TCP路由代理（第7层），基于Gevent，用Python进行配置。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;web开发的一些框架&lt;br&gt;1.Django&lt;/p&gt;
&lt;p&gt;Django是一个开源的Web应用框架，由Python写成，支持许多数据库引擎，可以让Web开发变得迅速和可扩展，并会不断的版本更新以匹配Python最新版本，如果是新手程序员，可以从这个框架入手。&lt;/p&gt;
&lt;p&gt;2.Flask&lt;/p&gt;
&lt;p&gt;Flask是一个轻量级的Web应用框架, 使用Python编写。基于 WerkzeugWSGI工具箱和 Jinja2模板引擎。使用 BSD 授权。&lt;/p&gt;
&lt;p&gt;Flask也被称为 “microframework” ，因为它使用简单的核心，用 extension 增加其他功能。Flask没有默认使用的数据库、窗体验证工具。然而，Flask保留了扩增的弹性，可以用Flask-extension加入这些功 能：ORM、窗体验证工具、文件上传、各种开放式身份验证技术。&lt;/p&gt;
&lt;p&gt;3.Web2py&lt;/p&gt;
&lt;p&gt;Web2py是一个用Python语言编写的免费的开源Web框架，旨在敏捷快速的开发Web应用，具有快速、可扩展、安全以及可移植的数据库驱动的应用，遵循LGPLv3开源协议。&lt;/p&gt;
&lt;p&gt;Web2py提供一站式的解决方案，整个开发过程都可以在浏览器上进行，提供了Web版的在线开发，HTML模版编写，静态文件的上传，数据库的编写的功能。其它的还有日志功能，以及一个自动化的admin接口。&lt;/p&gt;
&lt;p&gt;4.Tornado&lt;/p&gt;
&lt;p&gt;Tornado即是一个Web server（对此本文不作详述），同时又是一个类web.py的micro-framework，作为框架Tornado的思想主要来源于Web.py，大家在Web.py的网站首页也可以看到Tornado的大佬Bret Taylor的这么一段话（他这里说的FriendFeed用的框架跟Tornado可以看作是一个东西）：&lt;/p&gt;
&lt;p&gt;“[web.py inspired the] Web framework we use at FriendFeed [and] the webapp framework that ships with App Engine…”&lt;br&gt;因为有这层关系，后面不再单独讨论Tornado。&lt;/p&gt;
&lt;p&gt;5.CherryPy&lt;/p&gt;
&lt;p&gt;CherryPy是一种用于Python的、简单而非常有用的Web框架，其主要作用是以尽可能少的操作将Web服务器与Python代码连接，其功能包括内置的分析功能、灵活的插件系统以及一次运行多个HTTP服务器的功能，可与运行在最新版本的Python、Jython、Android上。&lt;/p&gt;
&lt;p&gt;Echarts 图表的类库&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Bar（柱状图/条形图） &lt;/li&gt;
&lt;li&gt;Bar3D（3D 柱状图） &lt;/li&gt;
&lt;li&gt;Boxplot（箱形图） &lt;/li&gt;
&lt;li&gt;EffectScatter（散点图） &lt;/li&gt;
&lt;li&gt;Funnel（漏斗图） &lt;/li&gt;
&lt;li&gt;Gauge（仪表盘） &lt;/li&gt;
&lt;li&gt;Geo（地理坐标系） &lt;/li&gt;
&lt;li&gt;Graph（关系图） &lt;/li&gt;
&lt;li&gt;HeatMap（热力图） &lt;/li&gt;
&lt;li&gt;Kline（K线图） &lt;/li&gt;
&lt;li&gt;Line（折线/面积图） &lt;/li&gt;
&lt;li&gt;Line3D（3D 折线图） &lt;/li&gt;
&lt;li&gt;Liquid（水球图） &lt;/li&gt;
&lt;li&gt;Map（地图） &lt;/li&gt;
&lt;li&gt;Parallel（平行坐标系） &lt;/li&gt;
&lt;li&gt;Pie（饼图） &lt;/li&gt;
&lt;li&gt;Polar（极坐标系） &lt;/li&gt;
&lt;li&gt;Radar（雷达图） &lt;/li&gt;
&lt;li&gt;Sankey（桑基图） &lt;/li&gt;
&lt;li&gt;Scatter（散点图） &lt;/li&gt;
&lt;li&gt;Scatter3D（3D 散点图） &lt;/li&gt;
&lt;li&gt;ThemeRiver（主题河流图） &lt;/li&gt;
&lt;li&gt;WordCloud（词云图）&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;原创地址：&lt;a href=&#34;https://mp.weixin.qq.com/s/6SJYooBuBhzsibeXS1mvWQ&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;https://mp.weixin.qq.com/s/6SJYooBuBhzsibeXS1mvWQ&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;当我们的ES集群搭建完成以后，我怎么能看到集群中各个节点状态以及主节点和健康情况呢，如下讲解使用curl命令来与ES集群进行交互、分别有查询主节点情况、集群状态、以及创建索引查看索引、查看分片以及对ES集群进行查询请求等操作。&lt;/p&gt;
&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;p&gt;CURL语法讲解&lt;/p&gt;
&lt;p&gt;RESTful API:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;curl  -X&amp;lt;VERB&amp;gt; &amp;apos;&amp;lt;PROTOCOL&amp;gt;://&amp;lt;HOST&amp;gt;:&amp;lt;PORT&amp;gt;/&amp;lt;PATH&amp;gt;?&amp;lt;QUERY_STRING&amp;gt;&amp;apos; -d &amp;apos;&amp;lt;BODY&amp;gt;&amp;apos;
-X：指定请求方式

&amp;lt;VERB&amp;gt;：GET,POST,PUT,DELETE   一般请求为GET、提交变更为POST、上传文件为PUT、删除操作为DELETE

&amp;lt;PROTOCOL&amp;gt;：协议，一般为HTTP协议

&amp;lt;HOST&amp;gt;：主机，可为主机的IP地址或Hostname

&amp;lt;PORT&amp;gt;：主机端口

&amp;lt;PATH&amp;gt;：路径，主机端口后的路径，如下几个路径：/_cat, /_search, /_cluster   /_cat路径覆盖了大多数的信息内容,/_search为搜索所有的索引和文档类型

&amp;lt;QUERY_STRING&amp;gt;：查询字符串匹配规则

-d：指定主体内容

&amp;lt;BODY&amp;gt;：json格式的请求主体&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;Elasticseearch基本查询语句&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;//查看_cat支持的信息
kibana: GET /_cat
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat&amp;apos;        

//查看主节点信息
kibana: GET /_cat/master?v
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat/master?v&amp;apos;        

//查看集群所有节点
kibana: GET /_cat/nodes?v
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat/nodes?v&amp;apos;        

//查看所有索引信息
kibana: GET /_cat/indices?v
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat/indices?v&amp;apos;        

//查看单个索引信息
kibana: GET /_cat/indices/movies?v
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat/indices/movies?v&amp;apos;        

//查看所有分片信息
kibana: GET /_cat/shards?v
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat/shards?v&amp;apos;        

//查看单个索引分片信息
kibana: GET /_cat/shards/movies?v
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat/shards/movies?v&amp;apos;        

//查看集群健康状态
kibana: GET /_cat/health?v
kibana: GET _cluster/health
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat/health?v&amp;apos;
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cluster/health?pretty&amp;apos;        

//查看插件
kibana: GET /_cat/plugins?v
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat/plugins?v&amp;apos;        

//查看所有索引文档总数
kibana: GET _all/_count
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_all/_count?pretty&amp;apos;        

//查看指定索引文档总数
kibana: GET movies/_count
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/movies/_count?pretty&amp;apos;        

//查看所有模板
kibana: GET _cat/templates
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat/templates?v&amp;apos;        

//查看状态为绿的索引
kibana: GET /_cat/indices?v&amp;amp;health=green
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat/indices?v&amp;amp;health=green&amp;apos;        

//查看movies索引元数据
kibana: GET movies
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/movies?pretty&amp;apos;        

//按照文档数量排序索引
kibana: GET _cat/indices?v&amp;amp;s=docs.count:desc
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat/indices?v&amp;amp;s=docs.count:desc&amp;apos;        

//查看各个索引占用内存大小并进行排序
kibana: 
bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;apos;http://192.168.31.215:9201/_cat/indices?v&amp;amp;h=i,tm&amp;amp;s=tm:desc&amp;apos;&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;Elasticsearch CURD语法&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;CURD&lt;/th&gt;
&lt;th&gt;请求方式&lt;/th&gt;
&lt;th&gt;主体&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;&lt;tr&gt;
&lt;td&gt;Create&lt;/td&gt;
&lt;td&gt;PUT&lt;/td&gt;
&lt;td&gt;/index/_create/id&lt;/td&gt;
&lt;td&gt;指定Document ID，创建文档，如果ID已存在，则失败&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Create&lt;/td&gt;
&lt;td&gt;POST&lt;/td&gt;
&lt;td&gt;/index/_create/id&lt;/td&gt;
&lt;td&gt;指定Document ID，创建文档，如果ID已存在，则失败&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Create&lt;/td&gt;
&lt;td&gt;POST&lt;/td&gt;
&lt;td&gt;/index/_doc&lt;/td&gt;
&lt;td&gt;自动生成ID，不会重复，重复提交则创建多个文档，文档版本都为1&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Index&lt;/td&gt;
&lt;td&gt;PUT&lt;/td&gt;
&lt;td&gt;/index/_doc/id&lt;/td&gt;
&lt;td&gt;如果ID不存在,则创建新的文档,如果ID存在,则删除现有文档后创建新的文档,版本+1,ID相同&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Index&lt;/td&gt;
&lt;td&gt;POST&lt;/td&gt;
&lt;td&gt;/index/_doc/id&lt;/td&gt;
&lt;td&gt;如果ID不存在,则创建新的文档,如果ID存在,则删除现有文档后创建新的文档,版本+1,ID相同&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Read&lt;/td&gt;
&lt;td&gt;GET&lt;/td&gt;
&lt;td&gt;/index/_doc/id&lt;/td&gt;
&lt;td&gt;查看Document ID为1的文档&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Update&lt;/td&gt;
&lt;td&gt;POST&lt;/td&gt;
&lt;td&gt;/index/_doc/id&lt;/td&gt;
&lt;td&gt;文档必须存在,否则更新失败,只能增量修改字段,不能减少字段,字段值可以随意修改,版本加1&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Delete&lt;/td&gt;
&lt;td&gt;Delete&lt;/td&gt;
&lt;td&gt;/index/_doc/id&lt;/td&gt;
&lt;td&gt;文档必须存在,否则删除返回”not_found”&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Delete&lt;/td&gt;
&lt;td&gt;Delete&lt;/td&gt;
&lt;td&gt;/index&lt;/td&gt;
&lt;td&gt;删除索引，索引内的文档也会被随之而删除,要删除的索引必须存在,否则返回 “404”&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;&lt;/table&gt;
&lt;p&gt;原创地址：&lt;a href=&#34;https://mp.weixin.qq.com/s/qZq_EV9q1LUUzOZeTzhA-g&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;https://mp.weixin.qq.com/s/qZq_EV9q1LUUzOZeTzhA-g&lt;/a&gt;&lt;/p&gt;

&lt;h2 id=&#34;1-在容器中搜索elasticsearch镜像-如图结果，一般选择最上面的一个。&#34;&gt;&lt;a href=&#34;#1-在容器中搜索elasticsearch镜像-如图结果，一般选择最上面的一个。&#34; class=&#34;headerlink&#34; title=&#34;1.在容器中搜索elasticsearch镜像,如图结果，一般选择最上面的一个。&#34;&gt;&lt;/a&gt;1.在容器中搜索elasticsearch镜像,如图结果，一般选择最上面的一个。&lt;/h2&gt;&lt;pre&gt;&lt;code&gt;sudo docker search elasticsearch&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;&lt;img src=&#34;https://erik.xyz/img/202005/07/2020-05-07_114446.jpg&#34; alt=&#34;&amp;#39;es图&amp;#39;&#34;&gt;&lt;/p&gt; &lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;h2 id=&#34;2-到elasticsearch官方网站查询elasticsearch的版本，我用的是最新版7-6-2&#34;&gt;&lt;a href=&#34;#2-到elasticsearch官方网站查询elasticsearch的版本，我用的是最新版7-6-2&#34; class=&#34;headerlink&#34; title=&#34;2.到elasticsearch官方网站查询elasticsearch的版本，我用的是最新版7.6.2&#34;&gt;&lt;/a&gt;2.到elasticsearch官方网站查询elasticsearch的版本，我用的是最新版7.6.2&lt;/h2&gt;&lt;h2 id=&#34;3-拉镜像到本地&#34;&gt;&lt;a href=&#34;#3-拉镜像到本地&#34; class=&#34;headerlink&#34; title=&#34;3.拉镜像到本地&#34;&gt;&lt;/a&gt;3.拉镜像到本地&lt;/h2&gt;&lt;pre&gt;&lt;code&gt;sudo docker pull elasticsearch:7.6.2&lt;/code&gt;&lt;/pre&gt;&lt;h2 id=&#34;4-查看本地镜像，找到elasticsearch，如下图&#34;&gt;&lt;a href=&#34;#4-查看本地镜像，找到elasticsearch，如下图&#34; class=&#34;headerlink&#34; title=&#34;4.查看本地镜像，找到elasticsearch，如下图&#34;&gt;&lt;/a&gt;4.查看本地镜像，找到elasticsearch，如下图&lt;/h2&gt;&lt;pre&gt;&lt;code&gt;sudo docker images&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;&lt;img src=&#34;https://erik.xyz/img/202005/07/2020-05-07_115053.jpg&#34; alt=&#34;&amp;#39;es图&amp;#39;&#34;&gt;&lt;/p&gt; &lt;h2 id=&#34;5-创建挂载本地目录&#34;&gt;&lt;a href=&#34;#5-创建挂载本地目录&#34; class=&#34;headerlink&#34; title=&#34;5.创建挂载本地目录&#34;&gt;&lt;/a&gt;5.创建挂载本地目录&lt;/h2&gt;&lt;pre&gt;&lt;code&gt;mkdir -p es/node1 es/node2 es/node3 &amp;amp;&amp;amp; mkdir es/node1/config es/node1/data es/node1/log es/node1/plugins es/node2/config es/node2/data es/node2/log es/node2/plugins es/node3/config es/node3/data es/node3/log es/node3/plugins&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;config存放配置文件&lt;/p&gt; &lt;p&gt;data存放数据&lt;/p&gt; &lt;p&gt;log存放日志&lt;/p&gt; &lt;p&gt;plugins存放插件&lt;/p&gt; &lt;p&gt;给目录开放读写权限&lt;/p&gt; &lt;pre&gt;&lt;code&gt;sudo chmod -R 777 es/node1 es/node2 es/node3&lt;/code&gt;&lt;/pre&gt;&lt;h2 id=&#34;6-创建配置文件&#34;&gt;&lt;a href=&#34;#6-创建配置文件&#34; class=&#34;headerlink&#34; title=&#34;6.创建配置文件&#34;&gt;&lt;/a&gt;6.创建配置文件&lt;/h2&gt;&lt;ul&gt; &lt;li&gt;&lt;p&gt;node1的配置文件 es/node1/config/config.yml&lt;/p&gt; &lt;pre&gt;&lt;code&gt;#集群名称 cluster.name: erik-es #当前该节点的名称 node.name: node1 #是不是有资格竞选主节点 node.master: true #是否存储数据 node.data: true #最大集群节点数 node.max_local_storage_nodes: 3 #给当前节点自定义属性（可以省略） #node.attr.rack: r1 #数据存档位置 path.data: /usr/share/elasticsearch/data #日志存放位置 path.logs: /usr/share/elasticsearch/log #是否开启时锁定内存（默认为是） #bootstrap.memory_lock: true #设置网关地址，我是被这个坑死了，这个地址我原先填写了自己的实际物理IP地址， #然后启动一直报无效的IP地址，无法注入9300端口，这里只需要填写0.0.0.0 network.host: 0.0.0.0 #设置其它结点和该结点交互的ip地址，如果不设置它会自动判断，值必须是个真实的ip地址，设置当前物理机地址, #如果是docker安装节点的IP将会是配置的IP而不是docker网管ip network.publish_host: 172.18.0.2 #设置映射端口 http.port: 9200 #内部节点之间沟通端口 transport.tcp.port: 9300 #集群发现默认值为127.0.0.1:9300,如果要在其他主机上形成包含节点的群集,如果搭建集群则需要填写 #es7.x 之后新增的配置，写入候选主节点的设备地址，在开启服务后可以被选为主节点，也就是说把所有的节点都写上 discovery.seed_hosts: [&amp;quot;172.18.0.2:9300&amp;quot;,&amp;quot;172.18.0.3:9301&amp;quot;,&amp;quot;172.18.0.4:9302&amp;quot;] #当你在搭建集群的时候，选出合格的节点集群，有些人说的太官方了， #其实就是，让你选择比较好的几个节点，在你节点启动时，在这些节点中选一个做领导者， #如果你不设置呢，elasticsearch就会自己选举，这里我们把三个节点都写上 cluster.initial_master_nodes: [&amp;quot;node1&amp;quot;,&amp;quot;node2&amp;quot;,&amp;quot;node3&amp;quot;] #在群集完全重新启动后阻止初始恢复，直到启动N个节点 #简单点说在集群启动后，至少复活多少个节点以上，那么这个服务才可以被使用，否则不可以被使用， gateway.recover_after_nodes: 2 #删除索引是是否需要显示其名称，默认为显示 #action.destructive_requires_name: true&lt;/code&gt;&lt;/pre&gt;&lt;/li&gt; &lt;li&gt;&lt;p&gt;node2的配置文件 es/node2/config/config.yml&lt;/p&gt; &lt;pre&gt;&lt;code&gt;#集群名称 cluster.name: erik-es #当前该节点的名称 node.name: node2 #是不是有资格竞选主节点 node.master: true #是否存储数据 node.data: true #最大集群节点数 node.max_local_storage_nodes: 3 #给当前节点自定义属性（可以省略） #node.attr.rack: r1 #数据存档位置 path.data: /usr/share/elasticsearch/data #日志存放位置 path.logs: /usr/share/elasticsearch/log #是否开启时锁定内存（默认为是） #bootstrap.memory_lock: true #设置网关地址，我是被这个坑死了，这个地址我原先填写了自己的实际物理IP地址， #然后启动一直报无效的IP地址，无法注入9300端口，这里只需要填写0.0.0.0 network.host: 0.0.0.0 #设置其它结点和该结点交互的ip地址，如果不设置它会自动判断，值必须是个真实的ip地址，设置当前物理机地址, #如果是docker安装节点的IP将会是配置的IP而不是docker网管ip network.publish_host: 172.18.0.3 #设置映射端口 http.port: 9201 #内部节点之间沟通端口 transport.tcp.port: 9301 #集群发现默认值为127.0.0.1:9300,如果要在其他主机上形成包含节点的群集,如果搭建集群则需要填写 #es7.x 之后新增的配置，写入候选主节点的设备地址，在开启服务后可以被选为主节点，也就是说把所有的节点都写上 discovery.seed_hosts: [&amp;quot;172.18.0.2:9300&amp;quot;,&amp;quot;172.18.0.3:9301&amp;quot;,&amp;quot;172.18.0.4:9302&amp;quot;] #当你在搭建集群的时候，选出合格的节点集群，有些人说的太官方了， #其实就是，让你选择比较好的几个节点，在你节点启动时，在这些节点中选一个做领导者， #如果你不设置呢，elasticsearch就会自己选举，这里我们把三个节点都写上 cluster.initial_master_nodes: [&amp;quot;node1&amp;quot;,&amp;quot;node2&amp;quot;,&amp;quot;node3&amp;quot;] #在群集完全重新启动后阻止初始恢复，直到启动N个节点 #简单点说在集群启动后，至少复活多少个节点以上，那么这个服务才可以被使用，否则不可以被使用， gateway.recover_after_nodes: 2 #删除索引是是否需要显示其名称，默认为显示 #action.destructive_requires_name: true&lt;/code&gt;&lt;/pre&gt;&lt;/li&gt; &lt;li&gt;&lt;p&gt;node3的配置文件 es/node3/config/config.yml&lt;/p&gt; &lt;pre&gt;&lt;code&gt;#集群名称 cluster.name: erik-es #当前该节点的名称 node.name: node3 #是不是有资格竞选主节点 node.master: true #是否存储数据 node.data: true #最大集群节点数 node.max_local_storage_nodes: 3 #给当前节点自定义属性（可以省略） #node.attr.rack: r1 #数据存档位置 path.data: /usr/share/elasticsearch/data #日志存放位置 path.logs: /usr/share/elasticsearch/log #是否开启时锁定内存（默认为是） #bootstrap.memory_lock: true #设置网关地址，我是被这个坑死了，这个地址我原先填写了自己的实际物理IP地址， #然后启动一直报无效的IP地址，无法注入9300端口，这里只需要填写0.0.0.0 network.host: 0.0.0.0 #设置其它结点和该结点交互的ip地址，如果不设置它会自动判断，值必须是个真实的ip地址，设置当前物理机地址, #如果是docker安装节点的IP将会是配置的IP而不是docker网管ip network.publish_host: 172.18.0.4 #设置映射端口 http.port: 9202 #内部节点之间沟通端口 transport.tcp.port: 9302 #集群发现默认值为127.0.0.1:9300,如果要在其他主机上形成包含节点的群集,如果搭建集群则需要填写 #es7.x 之后新增的配置，写入候选主节点的设备地址，在开启服务后可以被选为主节点，也就是说把所有的节点都写上 discovery.seed_hosts: [&amp;quot;172.18.0.2:9300&amp;quot;,&amp;quot;172.18.0.3:9301&amp;quot;,&amp;quot;172.18.0.4:9302&amp;quot;] #当你在搭建集群的时候，选出合格的节点集群，有些人说的太官方了， #其实就是，让你选择比较好的几个节点，在你节点启动时，在这些节点中选一个做领导者， #如果你不设置呢，elasticsearch就会自己选举，这里我们把三个节点都写上 cluster.initial_master_nodes: [&amp;quot;node1&amp;quot;,&amp;quot;node2&amp;quot;,&amp;quot;node3&amp;quot;] #在群集完全重新启动后阻止初始恢复，直到启动N个节点 #简单点说在集群启动后，至少复活多少个节点以上，那么这个服务才可以被使用，否则不可以被使用， gateway.recover_after_nodes: 2 #删除索引是是否需要显示其名称，默认为显示 #action.destructive_requires_name: true&lt;/code&gt;&lt;/pre&gt;&lt;/li&gt; &lt;/ul&gt; &lt;h2 id=&#34;7-创建网络&#34;&gt;&lt;a href=&#34;#7-创建网络&#34; class=&#34;headerlink&#34; title=&#34;7.创建网络&#34;&gt;&lt;/a&gt;7.创建网络&lt;/h2&gt;&lt;p&gt;如果需要安装kibana等其他，需要创建一个网络，名字任意取，让他们在同一个网络，使得elasticsearch和kibana通信，网络名称可以自定义&lt;/p&gt; &lt;pre&gt;&lt;code&gt;sudo docker network create es-net&lt;/code&gt;&lt;/pre&gt;&lt;p&gt; 查看已创建的网络，如下图&lt;/p&gt; &lt;pre&gt;&lt;code&gt;sudo docker network ls&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;&lt;img src=&#34;https://erik.xyz/img/202005/07/2020-05-07_125720.jpg&#34; alt=&#34;&#34;&gt;&lt;/p&gt; &lt;h2 id=&#34;8-创建节点&#34;&gt;&lt;a href=&#34;#8-创建节点&#34; class=&#34;headerlink&#34; title=&#34;8.创建节点&#34;&gt;&lt;/a&gt;8.创建节点&lt;/h2&gt;&lt;ul&gt; &lt;li&gt;&lt;p&gt;node1&lt;/p&gt; &lt;pre&gt;&lt;code&gt;sudo docker run --privileged -ti -e ES_JAVA_OPTS=&amp;quot;-Xms512m -Xmx512m&amp;quot; --network es-net -d -p 9200:9200 -p 9300:9300 -v /home/project/es/node1/config/elasticsearch.yml:/usr/share/elasticsearch/config/elasticsearch.yml -v /home/project/es/node1/plugins:/usr/share/elasticsearch/plugins -v /home/project/es/node1/data:/usr/share/elasticsearch/data -v /home/project/es/node1/log:/usr/share/elasticsearch/log --name es-node1 elasticsearch:7.6.2&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;这时候你会发现过会容器节点es-node1自动停止了。查查容器日志，如下&lt;br&gt;&lt;img src=&#34;https://erik.xyz/img/202005/07/2020-05-07_133110.jpg&#34; alt=&#34;&#34;&gt;&lt;/p&gt; &lt;p&gt;本地系统最大虚拟值太小，一般就是本地没有设置，而用了默认的，打开&lt;/p&gt; &lt;pre&gt;&lt;code&gt;sudo leafpad /etc/sysctl.conf&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;在sysctl.conf中找找vm.max_map_count，如果找不到就添加vm.max_map_count=262144&lt;br&gt;退出编辑，执行加载&lt;/p&gt; &lt;pre&gt;&lt;code&gt;sudo sysctl -p&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;重新启动es-node1&lt;/p&gt; &lt;p&gt;查询此时容器es-node1的IP地址&lt;/p&gt; &lt;pre&gt;&lt;code&gt;sudo docker inspect es-node1 | grep &amp;apos;&amp;quot;IPAddress&amp;quot;&amp;apos;&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;然后更改es-node1配置文件中的network.publish_host和discovery.seed_hostsd地址，其他两个节点也是如此。&lt;/p&gt; &lt;/li&gt; &lt;li&gt;&lt;p&gt;node2&lt;/p&gt; &lt;pre&gt;&lt;code&gt;sudo docker run --privileged -ti -e ES_JAVA_OPTS=&amp;quot;-Xms512m -Xmx512m&amp;quot; --network es-net -d -p 9201:9201 -p 9301:9301 -v /home/project/es/node2/config/elasticsearch.yml:/usr/share/elasticsearch/config/elasticsearch.yml -v /home/project/es/node2/plugins:/usr/share/elasticsearch/plugins -v /home/project/es/node2/data:/usr/share/elasticsearch/data -v /home/project/es/node2/log:/usr/share/elasticsearch/log --name es-node2 elasticsearch:7.6.2&lt;/code&gt;&lt;/pre&gt;&lt;/li&gt; &lt;/ul&gt; &lt;p&gt;改配置ip同node1&lt;/p&gt; &lt;ul&gt; &lt;li&gt;&lt;p&gt;node3&lt;/p&gt; &lt;pre&gt;&lt;code&gt;sudo docker run --privileged -ti -e ES_JAVA_OPTS=&amp;quot;-Xms512m -Xmx512m&amp;quot; --network es-net -d -p 9202:9202 -p 9302:9302 -v /home/project/es/node3/config/elasticsearch.yml:/usr/share/elasticsearch/config/elasticsearch.yml -v /home/project/es/node3/plugins:/usr/share/elasticsearch/plugins -v /home/project/es/node3/data:/usr/share/elasticsearch/data -v /home/project/es/node3/log:/usr/share/elasticsearch/log --name es-node3 elasticsearch:7.6.2&lt;/code&gt;&lt;/pre&gt;&lt;/li&gt; &lt;/ul&gt; &lt;p&gt;改配置ip同node1&lt;/p&gt; &lt;p&gt;修改完所有节点的配置文件后记得重启所有节点。&lt;/p&gt; &lt;h2 id=&#34;9-测试结果&#34;&gt;&lt;a href=&#34;#9-测试结果&#34; class=&#34;headerlink&#34; title=&#34;9.测试结果&#34;&gt;&lt;/a&gt;9.测试结果&lt;/h2&gt;&lt;p&gt;在浏览器端输入（ip是我本地的）&lt;a href=&#34;http://172.18.0.2:9200/_cat/nodes?pretty&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;http://172.18.0.2:9200/_cat/nodes?pretty&lt;/a&gt;&lt;br&gt;展示如下图&lt;/p&gt; &lt;p&gt;&lt;img src=&#34;https://erik.xyz/img/202005/07/2020-05-07_140004.jpg&#34; alt=&#34;&#34;&gt;&lt;/p&gt; &lt;p&gt;表示成功&lt;/p&gt; &lt;h2 id=&#34;10-安装Kibana&#34;&gt;&lt;a href=&#34;#10-安装Kibana&#34; class=&#34;headerlink&#34; title=&#34;10.安装Kibana&#34;&gt;&lt;/a&gt;10.安装Kibana&lt;/h2&gt;&lt;p&gt;在docker中拉取Kibana&lt;/p&gt; &lt;pre&gt;&lt;code&gt;sudo docker pull kibana:7.6.2&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;创建kibana目录，并添加文件&lt;/p&gt; &lt;pre&gt;&lt;code&gt;sudo chmod -R 777 kibana/config
leafpad kibana/config/kibana.yml&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;配置文件内容&lt;/p&gt; &lt;pre&gt;&lt;code&gt;#Kibana的映射端口 server.port: 5601
#网关地址 server.host: &amp;quot;0.0.0.0&amp;quot;
#Kibana实例对外展示的名称 server.name: &amp;quot;kibana-192.168.31.190&amp;quot;
#Elasticsearch的集群地址，也就是说所有的集群IP elasticsearch.hosts: [&amp;quot;http://172.18.0.2:9200&amp;quot;,&amp;quot;http://172.18.0.3:9201&amp;quot;,&amp;quot;http://172.18.0.4:9202&amp;quot;]
#设置页面语言，中文使用zh-CN，英文使用en i18n.locale: &amp;quot;zh-CN&amp;quot;
#这个配置还没理解清楚……………… xpack.monitoring.ui.container.elasticsearch.enabled: true&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;安装容器&lt;/p&gt; &lt;pre&gt;&lt;code&gt;sudo docker run --privileged -ti -d -p 5601:5601 -v /home/project/kibana/config/kibana.yml:/usr/share/kibana/config/kibana.yml --network es-net --name kibana kibana:7.6.2&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;成功后在浏览器输入地址（第一次启动会比较慢）&lt;a href=&#34;http://127.0.0.1:5601，展示如下图&#34; target=&#34;_blank&#34; rel=&#34;external nofollow noopener noreferrer&#34;&gt;http://127.0.0.1:5601，展示如下图&lt;/a&gt;&lt;/p&gt; &lt;p&gt;&lt;img src=&#34;https://erik.xyz/img/202005/07/2020-05-07_142240.jpg&#34; alt=&#34;&#34;&gt;&lt;/p&gt; &lt;p&gt;参考文章：&lt;a href=&#34;https://blog.csdn.net/gfk3009/article/details/104560431/&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;https://blog.csdn.net/gfk3009/article/details/104560431/&lt;/a&gt;&lt;/p&gt;

 &lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://kubernetes.io&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;Kubernetes&lt;/a&gt;  容器编排平台&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/kubernetes/kubernetes&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Kubernetes! 说起云原生应用，怎么能不提 Kubernetes 呢？Google 发明的 Kubernetes 无疑是最著名的基于容器的应用程序的容器编排平台，而且它还是一个开源工具。&lt;/p&gt;
&lt;p&gt;什么是容器编排平台？通常，一个容器引擎本身可以管理几个容器。但是，当你谈论数千个容器和数百个服务时，管理这些容器变得非常复杂。这就是容器编排引擎的用武之地。容器编排引擎通过自动化容器的部署、管理、网络和可用性来帮助管理大量的容器。&lt;/p&gt;
&lt;p&gt;Docker Swarm 和 Mesosphere Marathon 也是容器编排引擎，但是可以肯定地说，Kubernetes 已经赢得了这场比赛（至少现在是这样）。Kubernetes 还催生了像 OKD 这样的容器即服务（CaaS）平台，它是 Kubernetes 的 Origin 社区发行版，并成了 Red Hat OpenShift 的一部分。&lt;/p&gt;
&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://prometheus.io&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;Prometheus&lt;/a&gt;    系统和服务监控工具&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/prometheus/prometheus&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Prometheus 是 2012 年在 SoundCloud 上构建的一个开源的系统监控和告警工具。之后，许多公司和组织都采用了 Prometheus，并且该项目拥有非常活跃的开发者和用户群体。现在，它已经成为一个独立的开源项目，独立于公司之外进行维护。&lt;br&gt;理解 Prometheus 的最简单方法是可视化一个生产系统，该系统需要 24（小时）x 365（天）都可以正常运行。没有哪个系统是完美的，也有减少故障的技术（称为容错系统），但是，如果出现问题，最重要的是尽快发现问题。这就是像 Prometheus 这样的监控工具的用武之地。Prometheus 不仅仅是一个容器监控工具，但它在云原生应用公司中最受欢迎。此外，其他开源监视工具，包括 Grafana，都借助了 Prometheus。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://www.envoyproxy.io&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;Envoy&lt;/a&gt;        边缘和服务代理&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/envoyproxy/envoy&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Envoy（或 Envoy 代理）是专为云原生应用设计的开源的边缘代理和服务代理。由 Lyft 创建的 Envoy 是为单一服务和应用而设计的高性能的 C++ 开发的分布式代理，同时也是为由大量微服务组成的服务网格架构而设计的通信总线和通用数据平面。Envoy 建立在 Nginx、HAProxy、硬件负载均衡器和云负载均衡器等解决方案的基础上，Envoy 与每个应用相伴（并行）运行，并通过提供平台无关的方式提供通用特性来抽象网络。&lt;/p&gt;
&lt;p&gt;当基础设施中的所有服务流量都经过 Envoy 网格时，很容易就可以通过一致的可观测性来可视化问题域，调整整体性能，并在单个位置添加基础功能。基本上，Envoy 代理是一个可帮助组织为生产环境构建容错系统的服务网格工具。&lt;/p&gt;
&lt;p&gt;服务网格应用有很多替代方案，例如 Uber 的 Linkerd（下面会讨论）和 Istio。Istio 通过将其部署为 Sidecar 并利用了 Mixer 的配置模型，实现了对 Envoy 的扩展。Envoy 的显著特性有：&lt;/p&gt;
&lt;p&gt;◈ 包括所有的“入场筹码(table stakes)（LCTT 译注：引申为基础必备特性）”特性（与 Istio 这样的控制平面组合时）&lt;/p&gt;
&lt;p&gt;◈ 带载运行时 99% 数据可达到低延时&lt;/p&gt;
&lt;p&gt;◈ 可以作为核心的 L3/L4 过滤器，提供了开箱即用的 L7 过滤器&lt;/p&gt;
&lt;p&gt;◈ 支持 gRPC 和 HTTP/2（上行/下行）&lt;/p&gt;
&lt;p&gt;◈ 由 API 驱动，并支持动态配置和热重载&lt;/p&gt;
&lt;p&gt;◈ 重点关注指标收集、跟踪和整体可监测性&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://coreos.com/rkt/docs/latest&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;rkt&lt;/a&gt;        Pod 原生的容器引擎&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/rkt/rkt&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;rkt, 读作“rocket”，是一个 Pod 原生的容器引擎。它有一个命令行接口用来在 Linux 上运行容器。从某种意义上讲，它和其他容器如 Podman、Docker 和 CRI-O 相似。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://www.jaegertracing.io&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;Jaeger&lt;/a&gt;        分布式跟踪系统&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/jaegertracing/jaeger&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Jaeger 是一个开源的端到端的分布式追踪系统，适用于云端应用。在某种程度上，它是像 Prometheus 这样的监控解决方案。但它有所不同，因为其使用场景有所扩展：&lt;/p&gt;
&lt;p&gt;◈ 分布式事务监控&lt;/p&gt;
&lt;p&gt;◈ 性能和延时优化&lt;/p&gt;
&lt;p&gt;◈ 根因分析&lt;/p&gt;
&lt;p&gt;◈ 服务依赖性分析&lt;/p&gt;
&lt;p&gt;◈ 分布式上下文传播&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://linkerd.io&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;Linkerd&lt;/a&gt;    透明服务网格&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/linkerd/linkerd&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;像创建 Envoy 代理的 Lyft 一样，Uber 开发了 Linkerd 开源解决方案用于生产级的服务维护。在某些方面，Linkerd 就像 Envoy 一样，因为两者都是服务网格工具，旨在提供平台级的可观测性、可靠性和安全性，而无需进行配置或代码更改。&lt;/p&gt;
&lt;p&gt;但是，两者之间存在一些细微的差异。尽管 Envoy 和 Linkerd 充当代理并可以通过所连接的服务进行上报，但是 Envoy 并不像 Linkerd 那样被设计为 Kubernetes Ingress 控制器。Linkerd 的显著特点包括：&lt;/p&gt;
&lt;p&gt;◈ 支持多种平台（Docker、Kubernetes、DC/OS、Amazon ECS 或任何独立的机器）&lt;/p&gt;
&lt;p&gt;◈ 内置服务发现抽象，可以将多个系统联合在一起&lt;/p&gt;
&lt;p&gt;◈ 支持 gRPC、HTTP/2 和 HTTP/1.x请 求和所有的 TCP 流量&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://helm.sh&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;Helm&lt;/a&gt;        Kubernetes 包管理器&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/helm/helm&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Helm 基本上就是 Kubernetes 的包管理器。如果你使用过 Apache Maven、Maven Nexus 或类似的服务，你就会理解 Helm 的作用。Helm 可帮助你管理 Kubernetes 应用程序。它使用“Helm Chart”来定义、安装和升级最复杂的 Kubernetes 应用程序。Helm 并不是实现此功能的唯一方法；另一个流行的概念是 Kubernetes Operators，它被 Red Hat OpenShift 4 所使用。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://etcd.io&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;Etcd&lt;/a&gt;        分布式键值存储&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/etcd-io/etcd&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Etcd 是一个分布式的、可靠的键值存储，用于存储分布式系统中最关键的数据。其主要特性有：&lt;/p&gt;
&lt;p&gt;◈ 定义明确的、面向用户的 API（gRPC）&lt;/p&gt;
&lt;p&gt;◈ 自动 TLS，可选的客户端证书验证&lt;/p&gt;
&lt;p&gt;◈ 速度（可达每秒 10,000 次写入）&lt;/p&gt;
&lt;p&gt;◈ 可靠性（使用 Raft 实现分布式）&lt;/p&gt;
&lt;p&gt;Etcd 是 Kubernetes 和许多其他技术的默认的内置数据存储方案。也就是说，它很少独立运行或作为单独的服务运行；相反，它以集成到 Kubernetes、OKD/OpenShift 或其他服务中的形式来运作。还有一个 etcd Operator 可以用来管理其生命周期并解锁其 API 管理功能&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/cri-o/cri-o/blob/master/awesome.md&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;CRI-O&lt;/a&gt;    专门用于 Kubernetes 的轻量级运行时环境&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/cri-o/cri-o&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;CRI-O 是 Kubernetes 运行时接口的 OCI 兼容实现。CRI-O 用于各种功能，包括：&lt;/p&gt;
&lt;p&gt;◈ 使用 runc（或遵从 OCI 运行时规范的任何实现）和 OCI 运行时工具运行&lt;/p&gt;
&lt;p&gt;◈ 使用容器/镜像进行镜像管理&lt;/p&gt;
&lt;p&gt;◈ 使用容器/存储来存储和管理镜像层&lt;/p&gt;
&lt;p&gt;◈ 通过容器网络接口（CNI）来提供网络支持&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;原文章地址：&lt;a href=&#34;https://mp.weixin.qq.com/s/t4bXqZLtvm_Xc1RiPq7rEw&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;https://mp.weixin.qq.com/s/t4bXqZLtvm_Xc1RiPq7rEw&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;在使用openvas的过程中发生了一些小事情。&lt;br&gt;使用命令&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo openvas-check-setup&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;检查安装是否完整时，总是报错。提示说是nvt问题，反反复复，后来确认了才发现是数据更新问题。&lt;br&gt;用命令&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo greenbone-scapdata-sync&lt;/code&gt;&lt;/pre&gt;&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;p&gt;拉取数据库，开始是从2005年拉取数据，超时了，重新执行命令拉取。由于国外的数据，速度很慢，还是总是超时。没办法，拉到2020年的数据已经是大半夜了。&lt;/p&gt;
&lt;p&gt;获取证书&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo greenbone-certdata-sync&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;重建数据库&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo openvasmd --rebuild&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;创建用户和重置密码&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo openvasmd --create-user=erik --role=Admin &amp;amp;&amp;amp; sudo openvasmd --user=erik --new-password=123456&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;生成证书&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo openvas-manage-certs -a&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;启动greenbone security assistant        &lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo gsad --listen=127.0.0.1 --port=9392&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;运行openvas&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo openvasmd&lt;/code&gt;&lt;/pre&gt;&lt;p&gt; 再次检查安装&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo openvas-check-setup&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;  显示：It seems like your OpenVAS-9 installation is OK就表示安装成功。&lt;/p&gt;
&lt;p&gt;  在浏览器输入&lt;a href=&#34;https://127.0.0.1:9392访问登录&#34; target=&#34;_blank&#34; rel=&#34;external nofollow noopener noreferrer&#34;&gt;https://127.0.0.1:9392访问登录&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;偶然研究一下攻击wordpress的工具wpscan根据网上示范的教程，发现坑特别多。&lt;br&gt; 大部分都是老版本的教程，最新版命令有所改动，已经剔除–wordlist改为-P。&lt;br&gt;需要在官方网站注册生成密钥，本地使用。&lt;br&gt;另外密码字典需要自己用crunch生成,大部分弱密码都可以爆破。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;hr&gt;
&lt;p&gt;安装&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo pip3 install usbrip&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;&lt;img src=&#34;https://erik.xyz/img/202003/2020-03-28_142919.jpg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;
&lt;p&gt; 查询usb列表&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo usbrip events history -q -n 100&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;&lt;img src=&#34;https://erik.xyz/img/202003/2020-03-28_142845.jpg&#34; alt=&#34;&#34;&gt;&lt;/p&gt;

 &lt;p&gt;今天给一家公司投简历，问我用过openresty没，确实没用过，回答后没结果了。这就查了查。&lt;/p&gt;
&lt;p&gt;官方介绍如下：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;        OpenResty® 是一个基于 Nginx 与 Lua 的高性能 Web 平台，其内部集成了大量精良的 Lua 库、第三方模块以及大多数的依赖项。用于方便地搭建能够处理超高并发、扩展性极高的动态 Web 应用、Web 服务和动态网关。

OpenResty® 通过汇聚各种设计精良的 Nginx 模块（主要由 OpenResty 团队自主开发），从而将 Nginx 有效地变成一个强大的通用 Web 应用平台。这样，Web 开发人员和系统工程师可以使用 Lua 脚本语言调动 Nginx 支持的各种 C 以及 Lua 模块，快速构造出足以胜任 10K 乃至 1000K 以上单机并发连接的高性能 Web 应用系统。

OpenResty® 的目标是让你的Web服务直接跑在 Nginx 服务内部，充分利用 Nginx 的非阻塞 I/O 模型，不仅仅对 HTTP 客户端请求,甚至于对远程后端诸如 MySQL、PostgreSQL、Memcached 以及 Redis 等都进行一致的高性能响应。&lt;/code&gt;&lt;/pre&gt;  &lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;p&gt;  另外还有一篇博客专门介绍了一下&lt;a href=&#34;https://blog.openresty.com.cn/cn/how-or-alloc-mem&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;OpenResty 和 Nginx 如何分配和管理内存&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;  因为我用的是kali在官方提供的方法里安装源不支持，只能用包编译安装。&lt;/p&gt;
&lt;p&gt;  这里是下载不同系统和不同版本的页面 &lt;a href=&#34;https://openresty.org/cn/download.html&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;openresty&lt;/a&gt;&lt;br&gt;  &lt;img src=&#34;https://erik.xyz/img/202003/2020-03-26_020859.jpg&#34; alt=&#34;版本图片&#34;&gt;&lt;/p&gt;
&lt;p&gt;  源配置教程 &lt;a href=&#34;https://openresty.org/en/linux-packages.html&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;openresty&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;  &lt;img src=&#34;https://erik.xyz/img/202003/yum.jpg&#34; alt=&#34;源图片&#34;&gt;&lt;/p&gt;
&lt;p&gt;  我&lt;a href=&#34;https://openresty.org/download/openresty-1.15.8.3.tar.gz&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;下载&lt;/a&gt;的编译包&lt;/p&gt;
&lt;p&gt;  解压，后进入目录,执行如下命令（参数根据自己需要来添加）&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;./configure --prefix=/opt/openresty --with-pcre-jit --with-ipv6 --without-http_redis2_module --with-http_iconv_module --with-http_postgres_module -j8 --with-luajit&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;然后执行&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;如果电脑支持多核 make 工作的特性就用&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;make j2&lt;/code&gt;&lt;/pre&gt;&lt;/li&gt;
&lt;li&gt;&lt;p&gt;否则用&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;make&lt;/code&gt;&lt;/pre&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;以上执行完毕后，执行&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo make install&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;然后测试是否安装成功&lt;/p&gt;
&lt;p&gt;在任意目录创建work文件&lt;/p&gt;
&lt;p&gt;我是在/home/project/下创建文件work，并在work文件中创建conf和logs文件&lt;/p&gt;
&lt;p&gt;然后，在conf目录创建nginx.conf，并放入一下代码&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;worker_processes  1;
error_log logs/error.log;
events {
    worker_connections 1024;
}
http {
    server {
        listen 8080;
        location / {
            default_type text/html;
            content_by_lua_block {
                ngx.say(&amp;quot;&amp;lt;p&amp;gt;https://erik.xyz&amp;lt;/p&amp;gt;&amp;quot;)
            }
        }
    }
}&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;根据我的安装在work目录下，执行：/opt/openresty/nginx/sbin/nginx -p `pwd`/ -c conf/nginx.conf&lt;/p&gt;
&lt;p&gt;启动nginx，然后浏览器或者用curl命令访问本地8080端口，就可以看到定义好输出的网址。&lt;/p&gt;

 &lt;p&gt;根据&lt;a href=&#34;https://nosql-database.org&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;NoSQL官网&lt;/a&gt;查阅，结合网上资料做一个简单介绍。&lt;/p&gt;
&lt;h4 id=&#34;键值数据库&#34;&gt;&lt;a href=&#34;#键值数据库&#34; class=&#34;headerlink&#34; title=&#34;键值数据库&#34;&gt;&lt;/a&gt;键值数据库&lt;/h4&gt;&lt;ul&gt;
&lt;li&gt;&lt;p&gt;目前使用较多的&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://redis.io&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;redis&lt;/a&gt;（开源）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://memcached.org&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;memcached&lt;/a&gt;（开源）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;特点：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;基于内存数据处理，相对速度最快；数据存储结构最简单，只有key-value形式；对值的查询统计功能支持很弱；由于基于内存数据处理，数据持久性相对较弱。但，redis具备大数据管理能力；事务处理能力弱。&lt;/code&gt;&lt;/pre&gt;&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;h4 id=&#34;文档数据库&#34;&gt;&lt;a href=&#34;#文档数据库&#34; class=&#34;headerlink&#34; title=&#34;文档数据库&#34;&gt;&lt;/a&gt;文档数据库&lt;/h4&gt;&lt;/li&gt;
&lt;li&gt;&lt;p&gt;目前使用较多的&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://www.mongodb.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;mongodb&lt;/a&gt;（开源）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://www.couchbase.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;couchbase&lt;/a&gt;（开源）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;特点：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;mongodb基于硬盘数据处理，速度比sql数据库提高十几倍；couchbase基于内存处理；两者都具有很强的横向扩展能力；文档数据库的值具备复杂文档结构数据的处理能力，查询统计性能相对比键值数据库要强。具备大数据处理能力；无事务处理能力。&lt;/code&gt;&lt;/pre&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;列族数据库&#34;&gt;&lt;a href=&#34;#列族数据库&#34; class=&#34;headerlink&#34; title=&#34;列族数据库&#34;&gt;&lt;/a&gt;列族数据库&lt;/h4&gt;&lt;ul&gt;
&lt;li&gt;&lt;p&gt;目前使用较多的&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://cassandra.apache.org&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;cassandra&lt;/a&gt;（开源）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://hbase.apache.org&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;hbase&lt;/a&gt;（开源）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;特点：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;基于硬盘数据处理，主要用于大数据处理，写速度明显比读速度要快，整体读写速度较键值数据库、文档数据库要慢；有强大的数据查询统计功能；无事务处理能力。&lt;/code&gt;&lt;/pre&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;图数据库&#34;&gt;&lt;a href=&#34;#图数据库&#34; class=&#34;headerlink&#34; title=&#34;图数据库&#34;&gt;&lt;/a&gt;图数据库&lt;/h4&gt;&lt;ul&gt;
&lt;li&gt;&lt;p&gt;目前使用较多的&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://neo4j.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;neo4j&lt;/a&gt;（早期版本开源）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://orientdb.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;orientdb&lt;/a&gt;（开源）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;特点：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;基于硬盘的数据处理，侧重图（这里的图是数学里的“图论”，即一个包含若干个节点、节点之间存在边关系，节点和边可以附加相关属性的结合系统）数据查询计算。ACID事务&lt;/code&gt;&lt;/pre&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;多模式数据库&#34;&gt;&lt;a href=&#34;#多模式数据库&#34; class=&#34;headerlink&#34; title=&#34;多模式数据库&#34;&gt;&lt;/a&gt;多模式数据库&lt;/h4&gt;&lt;ul&gt;
&lt;li&gt;目前使用较多的&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://www.arangodb.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;ArangoDB&lt;/a&gt;（开源+商业）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;http://virtuoso.openlinksw.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;OpenLink Virtuoso&lt;/a&gt;（开源+商业）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;对象数据库&#34;&gt;&lt;a href=&#34;#对象数据库&#34; class=&#34;headerlink&#34; title=&#34;对象数据库&#34;&gt;&lt;/a&gt;对象数据库&lt;/h4&gt;&lt;ul&gt;
&lt;li&gt;目前使用较多的&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;http://db4o.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;db4o&lt;/a&gt;（开源）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;http://www.versant.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;versant&lt;/a&gt;（商业）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;网格和云数据库&#34;&gt;&lt;a href=&#34;#网格和云数据库&#34; class=&#34;headerlink&#34; title=&#34;网格和云数据库&#34;&gt;&lt;/a&gt;网格和云数据库&lt;/h4&gt;&lt;ul&gt;
&lt;li&gt;目前使用较多的&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://www.gridgain.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;gridgain&lt;/a&gt;（开源+商业）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://crate.io&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;cratedb&lt;/a&gt;（开源） &lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;XML数据库&#34;&gt;&lt;a href=&#34;#XML数据库&#34; class=&#34;headerlink&#34; title=&#34;XML数据库&#34;&gt;&lt;/a&gt;XML数据库&lt;/h4&gt;&lt;ul&gt;
&lt;li&gt;目前使用较多的&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://www.delltechnologies.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;EMC Documentum xDB&lt;/a&gt;（商业）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;http://exist-db.org&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;eXist&lt;/a&gt;（开源）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;多维数据库&#34;&gt;&lt;a href=&#34;#多维数据库&#34; class=&#34;headerlink&#34; title=&#34;多维数据库&#34;&gt;&lt;/a&gt;多维数据库&lt;/h4&gt;&lt;ul&gt;
&lt;li&gt;目前使用较多的&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;http://globalsdb.org&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;Globals&lt;/a&gt;（商业）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;http://www.intersystems.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;Intersystems Cache&lt;/a&gt;（商业） &lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;多值数据库&#34;&gt;&lt;a href=&#34;#多值数据库&#34; class=&#34;headerlink&#34; title=&#34;多值数据库&#34;&gt;&lt;/a&gt;多值数据库&lt;/h4&gt;&lt;ul&gt;
&lt;li&gt;目前使用较多的&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;http://www.revelation.com/index.php/features&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;OpenInsight&lt;/a&gt;（商业）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://www.rocketsoftware.com/products/rocket-u2&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;u2&lt;/a&gt;（商业）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;事件驱动数据库&#34;&gt;&lt;a href=&#34;#事件驱动数据库&#34; class=&#34;headerlink&#34; title=&#34;事件驱动数据库&#34;&gt;&lt;/a&gt;事件驱动数据库&lt;/h4&gt;&lt;ul&gt;
&lt;li&gt;目前使用较多的&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://eventstore.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;event store&lt;/a&gt;（开源）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;https://github.com/NEventStore/NEventStore&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;nevent store&lt;/a&gt;（开源）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;时间序列-流数据库&#34;&gt;&lt;a href=&#34;#时间序列-流数据库&#34; class=&#34;headerlink&#34; title=&#34;时间序列/流数据库&#34;&gt;&lt;/a&gt;时间序列/流数据库&lt;/h4&gt;&lt;ul&gt;
&lt;li&gt;目前使用较多的&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;http://axibase.com/products/axibase-time-series-database&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;Axibase&lt;/a&gt;（开源）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;http://kx.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;kdb+&lt;/a&gt;（个人版开源）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;科学、专业的数据库&#34;&gt;&lt;a href=&#34;#科学、专业的数据库&#34; class=&#34;headerlink&#34; title=&#34;科学、专业的数据库&#34;&gt;&lt;/a&gt;科学、专业的数据库&lt;/h4&gt;&lt;ul&gt;
&lt;li&gt;目前使用较多的&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;http://probcomp.csail.mit.edu/software/bayesdb&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;bayesdb&lt;/a&gt;（开源）&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;http://www.gpudb.com&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;gpudb&lt;/a&gt;（商业）&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;

 &lt;h3 id=&#34;查找&#34;&gt;&lt;a href=&#34;#查找&#34; class=&#34;headerlink&#34; title=&#34;查找&#34;&gt;&lt;/a&gt;查找&lt;/h3&gt;&lt;p&gt;1.顺序查找&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;思路：从线性表的第一个元素开始，逐个将线性表中的元素与被查元素进行比较，如果相等，则查找成功，停止查找；若整个线性表扫描完毕，仍未找到与被查元素相等的元素，则表示线性表中没有要查找的元素，查找失败。&lt;/li&gt;
&lt;li&gt;最好情况下，第一个元素就是要查找的元素，则比较次数为1次&lt;/li&gt;
&lt;li&gt;最坏情况下，最后一个元素才是要找的元素，或者在线性表中，没有要查找的元素，则需要与线性表中所有的元素比较，比较次数为n次&lt;/li&gt;
&lt;li&gt;平均情况下，大约需要比较n/2次&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;唯一选择：&lt;ul&gt;
&lt;li&gt;线性表为无序表，则不管是顺序存储结构，还是链式存储结构，都只能用顺序查找&lt;/li&gt;
&lt;li&gt;即使线性表是有序的，如果采用链式存储结构，也只能用顺序查找&lt;/li&gt;
&lt;/ul&gt;
2.二分查找&lt;/li&gt;
&lt;li&gt;满足条件&lt;ul&gt;
&lt;li&gt;用顺序存储结构&lt;/li&gt;
&lt;li&gt;线性表是有序的，有序是指元素按非递减排列，即从小到大排列，且允许相邻元素相等&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;对于长度为n的有序线性表，利用二分查找元素X的过程&lt;ul&gt;
&lt;li&gt;如果X的值与中间项的值相等，则查找成功，结束查找&lt;/li&gt;
&lt;li&gt;如果X小于中间项的值，则在线性表的前半部分以二分法继续查找&lt;/li&gt;
&lt;li&gt;如果X大于中间项的值，则在线性表的后半部分以二分法继续查找&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;顺序查找法每一次比较，只将查找范围减少1，而二分法查找，每比较一次，可将查找范围减少为原来的一半，效率大大提高。对于长度为n的有序线性表，在最坏情况下，二分法查找只需比较$log_{2}n$次&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;排序&#34;&gt;&lt;a href=&#34;#排序&#34; class=&#34;headerlink&#34; title=&#34;排序&#34;&gt;&lt;/a&gt;排序&lt;/h3&gt;&lt;p&gt;1.交换类排序&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;冒泡排序&lt;ul&gt;
&lt;li&gt;冒泡排序就是通过两两相邻数据元素之间的比较和交换，不断地消去逆序，直到所有数据元素有序为止&lt;/li&gt;
&lt;li&gt;最坏情况下，长度为n的线性表排序，冒泡排序需要比较的次数为n(n-1)/2&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;快速排序&lt;ul&gt;
&lt;li&gt;快速排序就是在待排序的n个元素中取一个元素K,以元素K作为分割标准，把所有小于K元素的数据元素都移到K前面，把所有大于K元素的数据元素都移到K后面。这样，以K为分界线，把线性表分割为两个子表，这称为一趟排序。然后，对K前后的两个子表分别重复上述过程。继续下去，直到分割的子表的长度为1为止。&lt;/li&gt;
&lt;li&gt;快速排序最坏的情况需要进行n(n-1)/2次比较，实际效率比冒泡排序高&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;2.插入类排序&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;插入排序是每次将一个待排序元素，按其元素值的大小插入到前面已经排好序的子表中的适当位置，直到全部元素插入完成为止&lt;/li&gt;
&lt;li&gt;简单插入排序&lt;ul&gt;
&lt;li&gt;把n个待排序的元素看成是一个有序表和一个无序表，开始时，有序表只包含一个元素，而无序表包含另外n-1个元素，每次取无序表中的第一个元素插入到有序表中的正确位置，使之成为增加一个元素的新的有序表。插入元素时，插入位置及其后的记录依次向后移动。最后有序表的长度为n，而无序表为空，此时排序完成&lt;/li&gt;
&lt;li&gt;最坏情况，简单插入排序需要n(n-1)/2次比较&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;希尔排序&lt;ul&gt;
&lt;li&gt;先取一个整数$d_{1} &amp;lt; n$，把全部数据元素分成$d_{1}$个组，所有距离为$d_{1}$倍数的元素放在一组中，组成了一个子序列，对每个子序列分别进行简单插入排序。然后取$d_{2} &amp;lt; d_{1}$重复上述分组和排序工作，直到$d_{i} = 1$，即所有记录在一组中为止&lt;/li&gt;
&lt;li&gt;希尔排序的效率与所选取的增量序列有关，最坏情况下，希尔排序需要比较的次数是$n ^{r}(1&amp;lt;r&amp;lt;2)$&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;3.选择类排序&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;通过每一趟从待排序序列中选出值最小的元素，顺序放在已安排好序的有序子表的后面，直到全部序列满足排序要求为止&lt;/li&gt;
&lt;li&gt;简单选择排序&lt;ul&gt;
&lt;li&gt;先从所有n个待排序的数据元素中选择最小的元素，将该元素与第1个元素交换，再从剩下的n-1个元素中选出最小的元素与第2个元素交换。重复这样的操作直到所有的元素有序为止&lt;/li&gt;
&lt;li&gt;简单选择排序法在最坏的情况下需要比较n(n-1)/2次&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;堆排序&lt;ul&gt;
&lt;li&gt;若有n个元素的序列$(h_{1},h_{2},\cdots h_{n})$，将元素按顺序组成一棵完全二叉树，当且仅当满足下列条件时称为堆。$ \begin{cases} h_{i} \geq h_{2i} \newline h_{i} \geq h_{2i+1} \end{cases}$ 或者$ \begin{cases} h_{i} \leq h_{2i} \newline h_{i} \leq h_{2i+1} \end{cases}$ 其中，$ i=1,2,3,\cdots,n/2 $&lt;/li&gt;
&lt;li&gt;第一种情况称为大根堆，所有节点的值大于或等于左右子节点的值。第二种情况称为小根堆，所有节点的值小于或等于左右子节点的值&lt;/li&gt;
&lt;li&gt;堆排序最坏情况需要$ nlog_{2}n$次比较&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;

 &lt;h3 id=&#34;树&#34;&gt;&lt;a href=&#34;#树&#34; class=&#34;headerlink&#34; title=&#34;树&#34;&gt;&lt;/a&gt;树&lt;/h3&gt;&lt;p&gt;树，不是我们常见的长在土里的树木，而是计算机语言中的一种结构。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;树是一种简单的非线性结构&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;父节点&lt;ul&gt;
&lt;li&gt;树结构中，每一个节点只有一个前件，称为该节点的父节点；没有前件的节点只有一个，称为树的根节点，简称树的根&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;子节点和叶子节点&lt;ul&gt;
&lt;li&gt;树结构中，每一个节点可以有多个后件，称为该节点的子节点。没有后件的节点称为叶子节点&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;度&lt;ul&gt;
&lt;li&gt;树结构中，每一个节点所拥有的后件个数称为该节点的度，所有节点中最大的度称为树的度&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;深度&lt;ul&gt;
&lt;li&gt;定义一棵树的根节点所在的层次为1，其他节点所在的层次等于它的父节点所在的层次加1。树的最大层次称为树的深度&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;子树&lt;ul&gt;
&lt;li&gt;在树中，以某节点的一个子节点为根构成的树称为该节点的一棵子树&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;在树中，树中的节点数等于树中所有节点的度之和再加1&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;二叉树&#34;&gt;&lt;a href=&#34;#二叉树&#34; class=&#34;headerlink&#34; title=&#34;二叉树&#34;&gt;&lt;/a&gt;二叉树&lt;/h3&gt;&lt;p&gt;1.特点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;二叉树可以为空，空的二叉树没有节点，非空二叉树有且只有一个根节点&lt;/li&gt;
&lt;li&gt;每个节点最多有两棵子树，即二叉树中不存在度大于2的节点&lt;/li&gt;
&lt;li&gt;二叉树的子树有左右之分，其次序不能任意颠倒&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;2.性质&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在二叉树的第k层上，最多有$ 2 ^{k-1}(k \geq 1)$个节点&lt;/li&gt;
&lt;li&gt;深度为m的二叉树中，最多有$ 2 ^{m}-1$个节点&lt;/li&gt;
&lt;li&gt;对任何一棵二叉树，度为0的节点（即叶节点）总是比度为2的节点多一个&lt;/li&gt;
&lt;li&gt;具有n个节点的二叉树，其深度至少为$[log_{2}n]+1$,其中$[log_{2}n]$表示取$log_{2}n$的整数部分&lt;/li&gt;
&lt;li&gt;具有n个节点的完全二叉树的深度为$[log_{2}n]+1$&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;3.满二叉树和完全二叉树&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;满二叉树&lt;ul&gt;
&lt;li&gt;满二叉树是指除最后一层外，每一层上的所有节点都有两个子节点的二叉树&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;完全二叉树&lt;ul&gt;
&lt;li&gt;完全二叉树是指除最后一层外，每一层上的节点数均达到最大值，在最后一层上只缺少右边的若干节点的二叉树&lt;/li&gt;
&lt;li&gt;满二叉树一定是完全二叉树，完全二叉树一般不是满二叉树&lt;/li&gt;
&lt;li&gt;完全二叉树特点&lt;/li&gt;
&lt;li&gt;叶子节点只可能在最后两层出现&lt;/li&gt;
&lt;li&gt;对于任一节点，若其右子树的深度为m，则该节点左子树的深度为m或为m+1&lt;/li&gt;
&lt;li&gt;二叉树采用链式存储结构。用于存储二叉树中元素的存储节点由数据域和指针域两部分构成&lt;/li&gt;
&lt;li&gt;二叉树的存储结构中每一个存储节点有两个指针域，因此，二叉树的链式存储结构也称为二叉链表。对于满二叉树与完全二叉树可以按层次进行顺序存储&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;二叉树的遍历&#34;&gt;&lt;a href=&#34;#二叉树的遍历&#34; class=&#34;headerlink&#34; title=&#34;二叉树的遍历&#34;&gt;&lt;/a&gt;二叉树的遍历&lt;/h3&gt;&lt;p&gt;1.前序遍历&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;首先访问根节点，然后遍历左子树，最后遍历右子树；并且在遍历左子树和右子树时，仍然先访问根节点，然后遍历左子树，最后遍历右子树&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;2.中序遍历&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;首先遍历左子树，然后访问根节点，最后遍历右子树。并且在遍历左子树和右子树时，仍然首先遍历左子树，然后访问根节点，最后遍历右子树&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;3.后序遍历&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;首先遍历左子树，然后遍历右子树，最后访问根节点；并且在遍历左子树和右子树时，仍然首先遍历左子树，然后遍历右子树，最后访问根节点&lt;ul&gt;
&lt;li&gt;如果已知一棵二叉树的前序遍历序列和中序遍历序列，可以唯一确定这棵二叉树；已知一棵二叉树的后序遍历序列和中序遍历序列，也可以唯一确定这棵二叉树。但是，已知一棵二叉树的前序列遍历序列和后序遍历序列，不能唯一确定这棵二叉树&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;

 &lt;h3 id=&#34;算法&#34;&gt;&lt;a href=&#34;#算法&#34; class=&#34;headerlink&#34; title=&#34;算法&#34;&gt;&lt;/a&gt;算法&lt;/h3&gt;&lt;p&gt;1.算法的基本特征&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;可行性&lt;ul&gt;
&lt;li&gt;步骤实现，执行结果达到预期&lt;ul&gt;
&lt;li&gt;确定性&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;步骤明确&lt;ul&gt;
&lt;li&gt;有穷性&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;有限的时间完成&lt;ul&gt;
&lt;li&gt;拥有足够的情报&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;拥有足够的输入信息和初始化信息&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;

&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;2.算法的复杂度&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;时间复杂度&lt;ul&gt;
&lt;li&gt;执行算法所需要的计算工作量&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;空间复杂度&lt;ul&gt;
&lt;li&gt;执行算法所需要的内存空间&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;数据结构&#34;&gt;&lt;a href=&#34;#数据结构&#34; class=&#34;headerlink&#34; title=&#34;数据结构&#34;&gt;&lt;/a&gt;数据结构&lt;/h3&gt;&lt;ol&gt;
&lt;li&gt;定义：有关联的数据元素的集合就是数据结构。&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;数据结构的概念&lt;ul&gt;
&lt;li&gt;根节点&lt;ul&gt;
&lt;li&gt;没有前件的节点&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;终端节点&lt;ul&gt;
&lt;li&gt;没有后件的节点&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;内部节点&lt;ul&gt;
&lt;li&gt;除了根节点和终端节点以外的节点&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;线性结构与非线性结构&#34;&gt;&lt;a href=&#34;#线性结构与非线性结构&#34; class=&#34;headerlink&#34; title=&#34;线性结构与非线性结构&#34;&gt;&lt;/a&gt;线性结构与非线性结构&lt;/h3&gt;&lt;p&gt;1.线性结构&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;有且只有一个根节点&lt;/li&gt;
&lt;li&gt;每个节点最多只有一个前件，也最多只有一个后件&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;2.非线性结构：不满足线性结构的两个条件就是非线性结构&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;树形结构&lt;/li&gt;
&lt;li&gt;网状结构&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;线性表&#34;&gt;&lt;a href=&#34;#线性表&#34; class=&#34;headerlink&#34; title=&#34;线性表&#34;&gt;&lt;/a&gt;线性表&lt;/h3&gt;&lt;p&gt;1.线性结构也被称为线性表&lt;/p&gt;
&lt;p&gt;2.非空线性表&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;只有一个根节点&lt;/li&gt;
&lt;li&gt;有且只有一个终端节点&lt;/li&gt;
&lt;li&gt;除根节点与终端节点外，其他所有节点有且只有一个前件，也有且只有一个后件&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;线性表的顺序存储&#34;&gt;&lt;a href=&#34;#线性表的顺序存储&#34; class=&#34;headerlink&#34; title=&#34;线性表的顺序存储&#34;&gt;&lt;/a&gt;线性表的顺序存储&lt;/h3&gt;&lt;p&gt;1.定义：线性表的顺序存储是将线性表中的元素一个接一个地存储在一片相邻的存储区域中，这种线性表也叫顺序表&lt;/p&gt;
&lt;p&gt;2.顺序表特征&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;线性表中所有元素所占的存储空间是连续的&lt;/li&gt;
&lt;li&gt;线性表中各数据元素在存储空间中是按逻辑顺序依次存放的&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;栈&#34;&gt;&lt;a href=&#34;#栈&#34; class=&#34;headerlink&#34; title=&#34;栈&#34;&gt;&lt;/a&gt;栈&lt;/h3&gt;&lt;p&gt;1.定义：栈是一种特殊的线性表，它所有的插入与删除都限定在表的同一端进行，允许插入与删除的一端称为栈顶，不允许插入与删除的另一端称为栈底。当栈中没有元素时，称为空栈。&lt;/p&gt;
&lt;p&gt;2.栈的修改原则是后进先出或先进后出&lt;/p&gt;
&lt;p&gt;3.栈的基本运算： 入栈、退栈、读栈顶元素&lt;/p&gt;
&lt;h3 id=&#34;队列&#34;&gt;&lt;a href=&#34;#队列&#34; class=&#34;headerlink&#34; title=&#34;队列&#34;&gt;&lt;/a&gt;队列&lt;/h3&gt;&lt;p&gt;1.定义：允许在一端进行插入，而在另一端进行删除的线性表&lt;/p&gt;
&lt;p&gt;2.允许进行删除运算的一端称为队头，允许进行插入运算的一端称为队尾&lt;/p&gt;
&lt;h3 id=&#34;顺序表和链表的对比&#34;&gt;&lt;a href=&#34;#顺序表和链表的对比&#34; class=&#34;headerlink&#34; title=&#34;顺序表和链表的对比&#34;&gt;&lt;/a&gt;顺序表和链表的对比&lt;/h3&gt;&lt;p&gt;1.顺序表&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;优点&lt;ul&gt;
&lt;li&gt;可随机存取表中的任意节点&lt;/li&gt;
&lt;li&gt;无需为表示节点间的逻辑关系额外增加存储空间&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;缺点&lt;ul&gt;
&lt;li&gt;顺序表的插入和删除运算效率很低&lt;/li&gt;
&lt;li&gt;顺序表的存储空间不便扩充&lt;/li&gt;
&lt;li&gt;顺序表不便于对存储空间的动态分配&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;2.链表&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;优点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在进行插入和删除运算时，只需要改变指针即可，不需要移动元素&lt;/li&gt;
&lt;li&gt;链表的存储空间易于扩充并且方便空间的动态分配&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;缺点&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;需要额外的空间来表示数据元素之间的逻辑关系，存储密度比顺序表低&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;链表类型&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;单向链表&lt;ul&gt;
&lt;li&gt;链表的链接方向是单向的，对链表的访问要通过顺序读取从头部开始，链表是使用指针进行构造的列表；又称为结点列表&lt;/li&gt;
&lt;li&gt;单个结点创建非常方便，普通的线性内存通常在创建的时候就需要设定数据的大小&lt;/li&gt;
&lt;li&gt;结点的删除非常方便，不需要像线性结构那样移动剩下的数据&lt;/li&gt;
&lt;li&gt;结点的访问方便，可以通过循环或者递归的方法访问到任意数据，但是平均的访问效率低于线性表&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;双向链表&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;每个数据结点中都有两个指针，分别指向直接后继和直接前驱。双向链表中的任意一个结点开始，都可以很方便地访问它的前驱结点和后继结点&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;环形链表&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;最后一个结点指向头结点，形成一个环。从循环链表中的任何一个结点出发都能找到任何其他结点&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;

 &lt;p&gt;kali用了有一段时间了，谈谈关于使用上的一些事吧。&lt;br&gt;目前我自己用的就是kali系统，安装在笔记本电脑上，中间也因为升级导致系统崩溃，自己也折腾过好几次。&lt;/p&gt;
&lt;hr&gt;
&lt;p&gt;安装完系统第一件事就是配置软件库&lt;/p&gt;
&lt;p&gt;编辑库源指定地址文件（没用leafpad是没安装，用vi或者vim也可以命令操作）&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo leafpad /etc/apt/sources.list&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;复制以下库地址  &lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;deb https://mirrors.ustc.edu.cn/kali kali-rolling main non-free contrib
deb-src https://mirrors.ustc.edu.cn/kali kali-rolling main non-free contrib

deb https://mirrors.tuna.tsinghua.edu.cn/debian/ buster main contrib non-free
deb https://mirrors.tuna.tsinghua.edu.cn/debian/ buster-updates main contrib non-free
deb https://mirrors.tuna.tsinghua.edu.cn/debian/ buster-backports main contrib non-free
deb https://mirrors.tuna.tsinghua.edu.cn/debian-security buster/updates main contrib non-free


deb http://mirrors.163.com/deepin/ unstable main contrib non-free
deb-src http://mirrors.163.com/deepin/ unstable main contrib non-free

deb [by-hash=force] http://packages.deepin.com/deepin stable main contrib non-free&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;然后就是更新 (注意，后面两个系统更新最好分开，中间万一出现兼容的选择问题会卸载一部分软件，把卸载的软件记录以下，出问题可以及时修复)&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo apt-get update &amp;amp;&amp;amp; sudo apt-get upgrade &amp;amp;&amp;amp; sudo apt-get dist-upgrade&lt;/code&gt;&lt;/pre&gt;&lt;hr&gt;
&lt;p&gt;配置环境（我这配置了java和go）&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;sudo leafpad /etc/profile&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;在文件最后添加（每个人的文件放置目录不同，根据自己的放置的位置调整）&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;JAVA_HOME=/usr/lib/jvm/jdk1.8.0_241
GO_ROOT=/usr/local/go
PATH=$JAVA_HOME/bin:$PATH:$GO_ROOT/bin
CLASSPATH=$JAVA_HOME/jre/lib/ext:$JAVA_HOME/lib/tools.jar
export PATH JAVA_HOME CLASSPATH&lt;/code&gt;&lt;/pre&gt;&lt;hr&gt;
&lt;p&gt;一般来说汉化版安装好后就可以啦，就是用的gnome桌面右键一直是英文的，后来后来找到一个插件nemo来汉化处理，一直用着不错。直到更新最新版本后，系统出现菜单栏展开是空白。各种汉化适配没能解决，当初一直没注意是插件的问题，没办法，用u盘系统备份了一下资料，重新安装系统。一步步安装插件才找到原因，时间是花了大代价，现在桌面还是右键英文。&lt;/p&gt;
&lt;hr&gt;
&lt;p&gt;kali本就是用于渗透测试或者攻防实验的，也不排除用来做“水下面的一些事”，工具嘛，看用的人。安装的新系统，能用的软件还是少部分，所以必须先去&lt;a href=&#34;https://www.kali.org&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;官网&lt;/a&gt;走一遭。找找&lt;a href=&#34;https://tools.kali.org&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;工具库&lt;/a&gt;如下图&lt;br&gt;&lt;img src=&#34;/img/202001/2020-01-22_21-35.jpg&#34; alt=&#34;kali工具&#34;&gt;&lt;br&gt;工具清单就是所有工具的列表&lt;/p&gt;
&lt;p&gt;元包实际就是一个类别工具分类包，可以一次性安装某方面相关的工具&lt;/p&gt;
&lt;p&gt;如下图&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/202001/2020-01-22_215720.jpg&#34; alt=&#34;kali元包工具&#34;&gt;&lt;/p&gt;
&lt;p&gt;反正我就是按元包安装的，比一个个找安装省事。。&lt;/p&gt;
&lt;p&gt;然后可以命令安装deepin-wine，搜索库文件qq、微信、企业微信、钉钉、搜狗输入法、wps、腾讯视频等其他软件，办公、开发、娱乐基本不成问题。还可以上github找找其他人从win系统移植出来的软件&lt;/p&gt;

 &lt;p&gt;来源：知乎，作者：大狐狸&lt;/p&gt;
&lt;p&gt;链接：&lt;a href=&#34;https://www.zhihu.com/question/36426051/answer/76031743&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;https://www.zhihu.com/question/36426051/answer/76031743&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;1.重构是程序员的主力技能。&lt;/p&gt;
&lt;p&gt;2.工作日志能提升脑容量。&lt;/p&gt;
&lt;p&gt;3.先用profiler调查，才有脸谈优化。&lt;/p&gt;
&lt;p&gt;4.注释贵精不贵多。杜绝大姨妈般的“例注”。漫山遍野的碎碎念注释，实际就是背景噪音。&lt;/p&gt;
&lt;p&gt;5.普通程序员+google=超级程序员。&lt;/p&gt;
&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;




&lt;p&gt;6.单元测试总是合算的。&lt;/p&gt;
&lt;p&gt;7.不要先写框架再写实现。最好反过来，从原型中提炼框架。&lt;/p&gt;
&lt;p&gt;8.代码结构清晰，其它问题都不算事儿。&lt;/p&gt;
&lt;p&gt;9.好的项目作风硬派，一键测试，一键发布，一键部署；烂的项目生性猥琐，口口相传，不立文字，神神秘秘。&lt;/p&gt;
&lt;p&gt;10.编码不要畏惧变化，要拥抱变化。&lt;/p&gt;
&lt;p&gt;11.常充电。程序员只有一种死法：土死的。&lt;/p&gt;
&lt;ol start=&#34;12&#34;&gt;
&lt;li&gt;编程之事，隔离是方向，起名是关键，测试是主角，调试是补充，版本控制是后悔药。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;13&#34;&gt;
&lt;li&gt;一行代码一个兵。形成建制才能有战斗力。单位规模不宜过大，千人班，万人排易成万人坑。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;14&#34;&gt;
&lt;li&gt;重构/优化/修复Bug，同时只能作一件。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;15&#34;&gt;
&lt;li&gt;简单模块注意封装，复杂模块注意分层。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;16&#34;&gt;
&lt;li&gt;人脑性能有限，整洁胜于杂乱。读不懂的代码，尝试整理下格式；不好用的接口，尝试重新封装下。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;17&#34;&gt;
&lt;li&gt;迭代速度决定工作强度。想多快好省，就从简化开发流程，加快迭代速度开始。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;18&#34;&gt;
&lt;li&gt;忘掉优化写代码，过早优化等同恶意破坏；忘掉代码作优化，优化要基于性能测试，而不是纠结于字里行间。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;19&#34;&gt;
&lt;li&gt;最好的工具是纸笔；其次好的是markdown。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;20&#34;&gt;
&lt;li&gt;leader问任务时间，若答不上来，可能是任务拆分还不够细。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;21&#34;&gt;
&lt;li&gt;宁可多算一周，不可少估一天。过于“乐观”容易让boss受惊吓。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;22&#34;&gt;
&lt;li&gt;最有用的语言是English。其次的可能是Python。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;23&#34;&gt;
&lt;li&gt;百闻不如一见。画出结果，一目了然。调试耗时将大大缩短。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;24&#34;&gt;
&lt;li&gt;资源、代码应一道受版本管理。资源匹配错误远比代码匹配错误更难排查。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;25&#34;&gt;
&lt;li&gt;不要基于想象开发， 要基于原型开发。原型的价值是快速验证想法，帮大家节省时间。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;26&#34;&gt;
&lt;li&gt;序列化首选明文文本 。诸如二进制、混淆、加密、压缩等等有需要时再加。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;27&#34;&gt;
&lt;li&gt;编译器永远比你懂微观优化。只能向它不擅长的方向努力。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;28&#34;&gt;
&lt;li&gt;不要定过大、过远、过细的计划。即使定了也没有用。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;29&#34;&gt;
&lt;li&gt;至少半数时间将花在集成上。时间，时间，时间总是不够。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;30&#34;&gt;
&lt;li&gt;与主流意见/方法/风格/习惯相悖时，先检讨自己最可靠。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;31&#34;&gt;
&lt;li&gt;出现bug主动查，不管是不是你的。这能让你业务能力猛涨、个人形象飙升; 如果你的bug被别人揪出来…..呵呵，那你会很被动～≧﹏≦&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;32&#34;&gt;
&lt;li&gt;不知怎么选技术书时就挑薄的。起码不会太贵，且你能看完。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;33&#34;&gt;
&lt;li&gt;git是最棒的。简单，可靠，免费。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;34&#34;&gt;
&lt;li&gt;仅对“可预测的非理性”抛断言。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;35&#34;&gt;
&lt;li&gt;Log要写时间与分类。并且要能重定向输出。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;36&#34;&gt;
&lt;li&gt;注释是稍差的文档。更好的是清晰的命名。让代码讲自己的故事。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;37&#34;&gt;
&lt;li&gt;造轮子是很好的锻炼方法。前提是你见过别的轮子。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;38&#34;&gt;
&lt;li&gt;code review最好以小组/结对的形式。对业务有一定了解，建议会更有价值（但不绝对）。而且不会成为负担。管理员个人review则很容易成team的瓶颈。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;39&#34;&gt;
&lt;li&gt;提问前先做调研。问不到点上既被鄙视，又浪费自己的时间。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol start=&#34;40&#34;&gt;
&lt;li&gt;永远别小看程序媛(╯3╰)&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;一、缘起&lt;/p&gt;
&lt;p&gt;1.1、鸿蒙&lt;/p&gt;
&lt;p&gt;在上古时期，天地初开，一群称之为 “运维” 的人们每天在一种叫作 “服务器” 的神秘盒子中创造属于他们的世界；他们在这个世界中每日劳作，一遍又一遍的写入他们的历史，比如搭建一个 nginx、布署一个 java web 应用…&lt;/p&gt;
&lt;p&gt;大多数人其实并没有那么聪明，他们所 “创造” 的事实上可能是有人已经创造过的东西，他们可能每天都在做着重复的劳动；久而久之，一些人厌倦了、疲惫了…又过了一段时间，一些功力深厚的老前辈创造了一些批量布署工具来帮助人们做一些重复性的劳动，这些工具被起名为 “Asible”、”Chef”、”Puppet” 等等…&lt;/p&gt;
&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;p&gt;而随着时代的发展，”世界” 变得越来越复杂，运维们需要处理的事情越来越多，比如各种网络、磁盘环境的隔离，各种应用服务的高可用…在时代的洪流下，运维们急需要一种简单高效的布署工具，既能有一定的隔离性，又能方便使用，并且最大程度降低重复劳动来提升效率。&lt;/p&gt;
&lt;p&gt;1.2、创世&lt;/p&gt;
&lt;p&gt;在时代洪流的冲击下，一位名为 “Solomon Hykes” 的人异军突起，他创造了一个称之为 Docker 的工具，Docker 被创造以后就以灭世之威向运维们展示了它的强大；一个战斗力只有 5 的运维只需要学习 Docker 很短时间就可以完成资深运维们才能完成的事情，在某些情况下以前需要 1 天才能完成的工作使用 Docker 后几分钟就可以完成；此时运维们已经意识到 “新的时代” 开启了，接下来 Docker 开源并被整个运维界人们使用，Docker 也不断地完善增加各种各样的功能，此后世界正式进入 “容器纪元”。&lt;/p&gt;
&lt;p&gt;二、纷争&lt;/p&gt;
&lt;p&gt;2.1、发展&lt;/p&gt;
&lt;p&gt;随着 Docker 的日益成熟，一些人开始在 Docker 之上创造更加强大的工具，一些人开始在 Docker 之下为其提供更稳定的运行环境…&lt;/p&gt;
&lt;p&gt;其中一个叫作 Google 的公司在 Docker 之上创建了名为 “Kuberentes” 的工具，Kubernetes 操纵 Docker 完成更加复杂的任务；Kubernetes 的出现更加印证了 Docker 的强大，以及 “容器纪元” 的发展正确性。&lt;/p&gt;
&lt;p&gt;2.2、野心&lt;/p&gt;
&lt;p&gt;当然这是一个充满利益的世界，Google 公司创造 Kubernetes 是可以为他们带来利益的，比如他们可以让 Kubernetes 深度适配他们的云平台，以此来增加云平台的销量等；此时 Docker 创始人也成立了一个公司，提供 Docker 的付费服务以及深度定制等；不过值得一提的是 Docker 公司提供的付费服务始终没有 Kubernetes 为 Google 公司带来的利益高，所以在利益的驱使下，Docker 公司开始动起了歪心思: 创造一个 Kubernetes 的替代品，利用用户粘度复制 Kubernetes 的成功，从 Google 嘴里抢下这块蛋糕！此时 Docker 公司只想把蛋糕抢过来，但是他们根本没有在意到暗中一群人创造了一个叫 “rkt” 的东西也在妄图夺走他们嘴里的蛋糕。&lt;/p&gt;
&lt;p&gt;2.3、冲突&lt;/p&gt;
&lt;p&gt;在一段时间的沉默后，Docker 公司又创造了 “Swarm” 这个工具，妄图夺走 Google 公司利用 Kubernetes 赢来的蛋糕；当然，Google 这个公司极其庞大，人数众多，而且在这个社会有很大的影响地位…&lt;/p&gt;
&lt;p&gt;终于，巨人苏醒了，Google 联合了 Redhat、Microsoft、IBM、Intel、Cisco 等公司决定对这个爱动歪脑筋的 Docker 公司进行制裁；当然制裁的手段不能过于暴力，那样会让别人落下把柄，成为别人的笑料，被人所不耻；最总他们决定制订规范，成立组织，明确规定 Docker 的角色，以及它应当拥有的能力，这些规范包括但不限于 CRI、CNI 等；自此之后各大公司宣布他们容器相关的工具只兼容 CRI 等相关标准，无论是 Docker 还是 rkt 等工具，只要实现了这些标准，就可以配合这些容器工具进行使用。&lt;/p&gt;
&lt;p&gt;三、成败&lt;/p&gt;
&lt;p&gt;自此之后，Docker 跌下神坛，各路大神纷纷创造满足 CRI 等规范的工具用来取代 Docker，Docker 丢失了往日一家独大的场面，最终为了顺应时代发展，拆分自己成为模块化组件；这些模块化组件被放置在 mobyproject 中方便其他人重复利用。&lt;/p&gt;
&lt;p&gt;时至今日，虽然 Docker 已经不负以前，但是仍然是容器化首选工具，因为 Docker 是一个完整的产品，它可以提供除了满足 CRI 等标准以外更加方便的功能；但是制裁并非没有结果，Google 公司借此创造了 cri-o 用来满足 CRI 标准，其他公司也相应创建了对应的 CRI 实现；为了进一步分化 Docker 势力，一个叫作 Podman 的工具被创建，它以 cri-o 为基础，兼容大部份 Docker 命令的方式开始抢夺 Dcoker 用户；到目前为止 Podman 已经可以在大部份功能上替代 Docker。&lt;/p&gt;
&lt;p&gt;原文地址：&lt;a href=&#34;https://mritd.me/2019/06/26/podman-history-of-container&#34; target=&#34;_blank&#34; target=&#34;_blank&#34; rel=&#34;noopener external nofollow noopener noreferrer&#34;&gt;https://mritd.me/2019/06/26/podman-history-of-container&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;设计模式 一书介绍了很多此类概念。当时，我还在学习面向对象 (OO)，因此我发现那本书中有许多概念都很难领会。但是，随着越来越熟悉 OO 概念 —— 尤其是接口和继承的使用 —— 我开始看到设计模式中的实际价值。作为一名应用程序开发人员，即使从不了解任何模式或者如何及何时使用这些模式，对您的职业生涯也没有什么大的影响。但是，我发现了解这些模式以及 developerWorks 文章 “五种常见 PHP 设计模式” 中介绍的那些模式的优秀知识后（请参阅 参考资料），您可以完成两件事情：&lt;/p&gt;
&lt;p&gt;启用高带宽会话&lt;br&gt;如果了解设计模式，您将能够更快地构建可靠的 OO 应用程序。但当整个开发团队知道各种模式时，您可以突然拥有非常高的带宽会话。您不再需要讨论将到处使用的所有类。相反，您可以与其他人谈论模式。“我要在这里引用一个单例（singleton），然后使用迭代器遍历对象集合，然后……” 比遍历构成这些模式的类、方法和接口快很多。单是通信效率一项就值得花时间以团队的形式通过会话来研究模式。&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;&lt;br&gt;减少痛苦的教训&lt;br&gt;每个设计模式都描述了一种经过验证的解决常见问题的方法。因此，您无需担心设计是不是正确的，只要您已经选择了提供所需优点的模式。&lt;br&gt;缺陷&lt;br&gt;有句谚语说得好：“当您手中拿着一把锤子时，所有事物看上去都像钉子”。当您认为自己找到一个优秀模式时，您可能会尝试到处使用它，即使在不应当使用它的位置。记住您必须考虑正在学习的模式的使用目的，不要为了使用模式而把这些模式强行应用到应用程序的各个部分中。&lt;/p&gt;
&lt;p&gt;本文将介绍可用于改进 PHP 代码的五个模式。每个模式都将介绍一个特定场景。可以在 下载 部分中获得这些模式的 PHP 代码。&lt;/p&gt;
&lt;p&gt;要求&lt;br&gt;要发挥本文的最大功效并使用示例，需要在计算机中安装以下软件：&lt;/p&gt;
&lt;p&gt;PHP V5 或更高版本（本文是使用 PHP V5.2.4 撰写的）&lt;br&gt;压缩程序，例如 WinZIP（用于压缩可下载的代码归档）&lt;br&gt;注：虽然您也可以使用纯文本编辑器，但是我发现拥有语法高亮显示和语法纠错功能的编辑器真的很有帮助。本文中的示例是使用 Eclipse PHP Development Tools (PDT) 编写的。&lt;/p&gt;
&lt;p&gt;——摘自《另外五个PHP设计模式》&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;命令链模式&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight plain&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;63&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;65&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;66&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;67&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;69&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;70&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;71&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;72&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&amp;lt;?php&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#x2F;**&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; * 艾瑞可erik&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; * https:&amp;#x2F;&amp;#x2F;erik.xyz&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; * 命令链模式&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; * Interface ICommand&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; *&amp;#x2F;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;interface ICommand&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    function onCommand($name, $args);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;class CommandChain&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    private $_command &amp;#x3D; [];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static function load()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return new CommandChain();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public function addCommand($cmd)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        $this-&amp;gt;_command[] &amp;#x3D; $cmd;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public function runCommand($name, $args)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        foreach ($this-&amp;gt;_command as $cmd) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            if ($cmd-&amp;gt;onCommand($name, $args)) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;                return;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;class UserCommand implements ICommand&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static function load()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return new UserCommand();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public function OnCommand($name, $args)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        if ($name !&amp;#x3D; &amp;#39;addUser&amp;#39;) return false;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        echo(&amp;quot;UserCommand handling &amp;#39;addUser&amp;#39;\n&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return true;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;class MailCommand implements ICommand&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public static function load()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return new MailCommand();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    public function onCommand($name, $args)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        if ($name !&amp;#x3D; &amp;#39;mail&amp;#39;) return false;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        echo(&amp;quot;MailCommand handling &amp;#39;mail&amp;#39;\n&amp;quot;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        return true;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$cc &amp;#x3D; CommandChain::load();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$cc-&amp;gt;addCommand(UserCommand::load());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$cc-&amp;gt;addCommand(MailCommand::load());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$cc-&amp;gt;runCommand(&amp;#39;addUser&amp;#39;, null);&lt;/span&g